 function exportDocuments(){const state=app().getState(),rows=documentRows(state,ui.document.kind),headers=['Numéro','Type','Client','Objet','Émission','Échéance','HT','TVA','TTC','Statut'],csv=[headers,...rows.map(row=>[row.number||'',typeLabels[row.document_type]||row.document_type,clientName(clientFor(state,row.client_id)),row.subject||'',row.issue_date||'',row.validity_date||row.due_date||'',row.total_excl_tax,row.total_tax,row.total_incl_tax,statusLabels[effectiveDocumentStatus(row,state)]||effectiveDocumentStatus(row,state)])].map(line=>line.map(value=>`"${String(value??'').replaceAll('"','""')}"`).join(';')).join('\r\n'),url=URL.createObjectURL(new Blob(['\ufeff'+csv],{type:'text/csv;charset=utf-8'})),link=document.createElement('a');link.href=url;link.download=`piloz-${ui.document.kind==='quote'?'devis':'factures'}-${iso(new Date())}.csv`;link.click();URL.revokeObjectURL(url);}
