 function selectField(label,name,options,value='',full=false){return`<label class="modern-field ${full?'full':''}"><span>${esc(label)}</span><select name="${esc(name)}">${options.map(([id,text])=>`<option value="${esc(id)}" ${String(id)===String(value)?'selected':''}>${esc(text)}</option>`).join('')}</select></label>`;}
 function openOpportunity(id=''){const state=app().getState(),item=(state.data.opportunities||[]).find(x=>x.id===id)||{},stages=(state.data.pipelineStages||[]).map(x=>[x.slug,x.name]),clients=(state.data.clients||[]).map(x=>[x.id,`${x.relationship_type==='prospect'?'Prospect':'Client'} · ${clientName(x)}`]),contacts=(state.data.clientContacts||[]).map(x=>[x.id,`${[x.first_name,x.last_name].filter(Boolean).join(' ')} · ${clientName(clientFor(state,x.client_id))}`]),members=(state.data.members||[]).map(x=>[x.user_id,x.user_id===global.PilozRuntime.session.user_id?'Moi':`${x.user_id.slice(0,8)} · ${x.role}`]),nextAction=item.next_action_at?new Date(item.next_action_at).toISOString().slice(0,16):'',docs=(state.data.documents||[]).filter(x=>x.opportunity_id===id),activities=(state.data.activities||[]).filter(x=>x.opportunity_id===id).slice(0,5),reminders=(state.data.reminders||[]).filter(x=>x.opportunity_id===id).slice(0,5),attachments=(state.data.attachments||[]).filter(x=>x.entity_type==='opportunity'&&x.entity_id===id);showDrawer(id?'Modifier l’opportunité':'Nouvelle opportunité',`<form id="modern-opportunity-form" class="modern-form" onsubmit="event.preventDefault();PilozModern.saveOpportunity('${id}')">${field('Nom *','name',item.name,'text','required',true)}${selectField('Client ou prospect','client_id',[['','Aucun'],...clients],item.client_id)}${selectField('Contact','contact_id',[['','Aucun'],...contacts],item.contact_id)}${selectField('Étape','stage',stages.length?stages:[['prospecting','Prospection']],item.stage||'prospecting')}${field('Montant estimé','amount',item.amount||0,'number','min="0" step="0.01"')}${field('Probabilité (%)','probability',item.probability??10,'number','min="0" max="100" step="0.01"')}${field('Clôture prévue','expected_close_date',item.expected_close_date,'date')}${field('Prochaine action','next_action_at',nextAction,'datetime-local')}${selectField('Responsable','assigned_user_id',[['','Non attribué'],...members],item.assigned_user_id||global.PilozRuntime.session.user_id)}<label class="modern-field full"><span>Notes</span><textarea name="notes">${esc(item.notes||'')}</textarea></label><div class="modern-form-actions">${button('Annuler','PilozModern.closeDrawer()')}${button('Enregistrer','', 'btn-p','type="submit"')}</div></form>${id?`<section class="phase1-card"><h3>Actions commerciales</h3><div class="actions">${button('Créer un devis',`PilozModern.newOpportunityDocument('${id}','quote')`,'btn-ghost')}${button('Créer une facture',`PilozModern.newOpportunityDocument('${id}','invoice')`,'btn-ghost')}${button('Ajouter une activité',`PilozModern.openActivity('${id}')`,'btn-ghost')}${button('Programmer une relance',`PilozModern.openReminder('','${id}')`,'btn-ghost')}${button('Ajouter une note',`PilozModern.openActivity('${id}','note')`,'btn-ghost')}<label class="btn btn-ghost">Ajouter une pièce jointe<input type="file" hidden onchange="PilozModern.uploadOpportunityAttachment('${id}',this.files[0])"></label></div><h3>Documents liés</h3>${docs.map(x=>`<button class="erp-row-button" onclick="PilozApp.editDocument('${x.id}')"><span><b>${esc(x.number||typeLabels[x.document_type]||'Brouillon')}</b><small>${esc(typeLabels[x.document_type]||x.document_type)}</small></span><strong>${money(x.total_incl_tax)}</strong></button>`).join('')||'<p>Aucun document lié.</p>'}<h3>Historique</h3>${[...activities.map(x=>({date:x.created_at,label:x.subject})),...reminders.map(x=>({date:x.created_at,label:x.subject}))].sort((a,b)=>String(b.date).localeCompare(String(a.date))).slice(0,6).map(x=>`<p><b>${esc(x.label)}</b><br><small>${datetime(x.date)}</small></p>`).join('')||'<p>Aucune activité.</p>'}${attachments.length?`<p>${attachments.length} pièce(s) jointe(s)</p>`:''}</section>`:''}`);}
 async function saveOpportunity(id){if(ui.busy)return;const form=document.getElementById('modern-opportunity-form'),data=Object.fromEntries(new FormData(form)),state=app().getState();data.company_id=state.companyId;data.client_id=data.client_id||null;data.contact_id=data.contact_id||null;data.amount=Number(data.amount)||0;data.probability=Number(data.probability)||0;data.expected_close_date=data.expected_close_date||null;data.next_action_at=data.next_action_at?new Date(data.next_action_at).toISOString():null;data.assigned_user_id=data.assigned_user_id||null;ui.busy=true;try{id?await api().update('opportunities',id,data):await api().insert('opportunities',data);closeDrawer();await app().refresh();notify('Opportunité enregistrée.','success');}catch(error){notify(error.message,'error');}finally{ui.busy=false;}}
 async function moveOpportunity(id,stage){const state=app().getState(),target=(state.data.pipelineStages||[]).find(x=>x.slug===stage);try{await api().update('opportunities',id,{stage,probability:target?.probability??0,closed_at:target?.is_won||target?.is_lost?new Date().toISOString():null});await app().refresh();}catch(error){notify(error.message,'error');}}
 function pipelineBoard(state,opportunities=state.data.opportunities||[]){const stages=(state.data.pipelineStages||[]).length?state.data.pipelineStages:[{slug:'prospecting',name:'Prospection',probability:10},{slug:'qualification',name:'Qualification',probability:25},{slug:'quote_preparation',name:'Devis en préparation',probability:40},{slug:'quote_sent',name:'Devis envoyé',probability:60},{slug:'won',name:'Gagné',probability:100},{slug:'invoicing',name:'Facturation',probability:85},{slug:'collected',name:'Encaissé',probability:100},{slug:'lost',name:'Perdu',probability:0}];return`<div class="modern-kanban">${stages.map(stage=>{const rows=opportunities.filter(x=>x.stage===stage.slug),total=rows.reduce((s,x)=>s+Number(x.amount||0),0);return`<section class="modern-kanban-column" ondragover="event.preventDefault()" ondrop="PilozModern.moveOpportunity(event.dataTransfer.getData('text/plain'),'${stage.slug}')"><header class="modern-kanban-head"><h2>${esc(stage.name)}</h2><span>${rows.length} · ${money(total)}</span></header>${rows.map(row=>{const acts=(state.data.activities||[]).filter(x=>x.opportunity_id===row.id).sort((a,b)=>String(b.created_at).localeCompare(String(a.created_at))),docs=(state.data.documents||[]).filter(x=>x.opportunity_id===row.id),quotes=docs.filter(x=>x.document_type==='quote').length,invoices=docs.filter(x=>['invoice','deposit_invoice','balance_invoice'].includes(x.document_type)).length;return`<article class="modern-opportunity" draggable="true" ondragstart="event.dataTransfer.setData('text/plain','${row.id}')" onclick="PilozModern.openOpportunity('${row.id}')"><b>${esc(row.name)}</b><p>${esc(clientName(clientFor(state,row.client_id)))}</p><small>${row.next_action_at?'Prochaine action '+datetime(row.next_action_at):'Aucune prochaine action'} · ${acts[0]?'Dernière activité '+datetime(acts[0].created_at):'Aucune activité'}</small><small>${row.assigned_user_id===global.PilozRuntime.session.user_id?'Responsable : moi':'Responsable : '+esc(row.assigned_user_id?.slice(0,8)||'non attribué')} · ${quotes} devis · ${invoices} facture(s)</small><footer><span>${money(row.amount)}</span><span>${Number(row.probability??stage.probability)||0} %</span></footer></article>`;}).join('')}</section>`;}).join('')}</div>`;}
 function setOpportunityView(view){ui.crmView=view==='pipeline'?'pipeline':'list';storage.set('piloz_crm_view',ui.crmView);app().render();}
 function renderPipeline(state){ui.crmView='pipeline';renderOpportunities(state);}
 function renderOpportunities(state){const rows=(state.data.opportunities||[]).filter(x=>!ui.crmSearch||[x.name,clientName(clientFor(state,x.client_id)),x.stage].some(v=>String(v||'').toLocaleLowerCase('fr').includes(ui.crmSearch.toLocaleLowerCase('fr')))),switcher=`<div class="modern-view-tabs"><button class="modern-view-tab ${ui.crmView==='list'?'active':''}" onclick="PilozModern.setOpportunityView('list')">Liste</button><button class="modern-view-tab ${ui.crmView==='pipeline'?'active':''}" onclick="PilozModern.setOpportunityView('pipeline')">Pipeline</button></div>`;document.getElementById('main').innerHTML=header('Opportunités','Montants, probabilités, prochaines actions et documents liés.',button('Nouvelle opportunité','PilozModern.openOpportunity()','btn-p'))+switcher+`<div class="modern-toolbar"><input type="search" placeholder="Rechercher une opportunité" value="${esc(ui.crmSearch)}" oninput="PilozModern.setCrmSearch(this.value)"></div>`+(ui.crmView==='pipeline'?pipelineBoard(state,rows):`<div class="modern-table-shell">${rows.length?`<table class="modern-table"><thead><tr><th>Opportunité</th><th>Client</th><th>Étape</th><th>Montant</th><th>Probabilité</th><th>Clôture prévue</th><th>Prochaine action</th><th>Devis</th><th>Factures</th></tr></thead><tbody>${rows.map(row=>{const docs=(state.data.documents||[]).filter(x=>x.opportunity_id===row.id),quotes=docs.filter(x=>x.document_type==='quote'),invoices=docs.filter(x=>['invoice','deposit_invoice','balance_invoice'].includes(x.document_type)),next=(state.data.reminders||[]).filter(x=>x.opportunity_id===row.id&&x.status==='pending').sort((a,b)=>String(a.due_at).localeCompare(String(b.due_at)))[0],nextDate=next?.due_at||row.next_action_at;return`<tr ondblclick="PilozModern.openOpportunity('${row.id}')"><td class="primary">${esc(row.name)}</td><td>${esc(clientName(clientFor(state,row.client_id)))}</td><td>${statusBadge(row.stage)}</td><td class="money">${money(row.amount)}</td><td>${Number(row.probability)||0} %</td><td>${date(row.expected_close_date)}</td><td>${nextDate?datetime(nextDate):'—'}</td><td>${quotes.length} · ${money(quotes.reduce((s,x)=>s+Number(x.total_excl_tax),0))}</td><td>${invoices.length} · ${money(invoices.reduce((s,x)=>s+Number(x.total_excl_tax),0))}</td></tr>`;}).join('')}</tbody></table>`:empty('Aucune opportunité','Ajoutez une opportunité pour démarrer le suivi commercial.',button('Créer','PilozModern.openOpportunity()','btn-p'))}</div>`);}
 function setCrmSearch(value){ui.crmSearch=value;app().render();}
 function crmOverview(state){const open=(state.data.opportunities||[]).filter(x=>!['collected','lost'].includes(x.stage)),pipeline=open.reduce((s,x)=>s+Number(x.amount||0),0),weighted=open.reduce((s,x)=>s+Number(x.amount||0)*Number(x.probability||0)/100,0),today=iso(new Date()),due=(state.data.reminders||[]).filter(x=>x.status==='pending'&&String(x.due_at).slice(0,10)<=today);document.getElementById('main').innerHTML=header('Suivi commercial','Prospects, opportunités, activités et relances réunis.',button('Nouvelle opportunité','PilozModern.openOpportunity()','btn-p'))+`<div class="modern-kpis">${kpi('Opportunités ouvertes',open.length)}${kpi('Pipeline brut',money(pipeline))}${kpi('Pipeline pondéré',money(weighted))}${kpi('Relances à traiter',due.length)}</div><div class="erp-grid-2"><section class="phase1-card"><h2>Prochaines actions</h2>${due.slice(0,8).map(x=>`<button class="erp-row-button" onclick="PilozApp.go('crm/reminders')"><span><b>${esc(x.subject)}</b><small>${datetime(x.due_at)}</small></span></button>`).join('')||'<p>Aucune relance en attente.</p>'}</section><section class="phase1-card"><h2>Opportunités récentes</h2>${open.slice(0,8).map(x=>`<button class="erp-row-button" onclick="PilozModern.openOpportunity('${x.id}')"><span><b>${esc(x.name)}</b><small>${esc(clientName(clientFor(state,x.client_id)))}</small></span><strong>${money(x.amount)}</strong></button>`).join('')||'<p>Aucune opportunité ouverte.</p>'}</section></div>`;}
 function openActivity(opportunityId='',activityType='call'){const state=app().getState(),opportunities=(state.data.opportunities||[]).map(x=>[x.id,x.name]),clients=(state.data.clients||[]).map(x=>[x.id,clientName(x)]),opportunity=opportunityFor(state,opportunityId);showDrawer(activityType==='note'?'Ajouter une note':'Nouvelle activité',`<form id="modern-activity-form" class="modern-form" onsubmit="event.preventDefault();PilozModern.saveActivity()">${selectField('Type','activity_type',[['call','Appel'],['email','E-mail'],['meeting','Rendez-vous'],['task','Tâche'],['note','Note'],['other','Autre']],activityType)}${field('Objet *','subject',activityType==='note'?'Note commerciale':'','text','required')}${selectField('Opportunité','opportunity_id',[['','Aucune'],...opportunities],opportunityId)}${selectField('Client','client_id',[['','Aucun'],...clients],opportunity?.client_id||'')}${field('Planifiée le','scheduled_at','','datetime-local')}<label class="modern-field full"><span>Description</span><textarea name="description"></textarea></label><div class="modern-form-actions">${button('Annuler','PilozModern.closeDrawer()')}${button('Enregistrer','', 'btn-p','type="submit"')}</div></form>`);}
 async function saveActivity(){const data=Object.fromEntries(new FormData(document.getElementById('modern-activity-form'))),state=app().getState();data.company_id=state.companyId;data.opportunity_id=data.opportunity_id||null;data.client_id=data.client_id||null;data.scheduled_at=data.scheduled_at?new Date(data.scheduled_at).toISOString():null;try{await api().insert('activities',data);closeDrawer();await app().refresh();notify('Activité enregistrée.','success');}catch(error){notify(error.message,'error');}}
 function renderActivities(state){const rows=state.data.activities||[];document.getElementById('main').innerHTML=header('Activités','Appels, rendez-vous, tâches, e-mails et notes commerciales.',button('Nouvelle activité','PilozModern.openActivity()','btn-p'))+`<div class="modern-table-shell">${rows.length?`<table class="modern-table"><thead><tr><th>Date</th><th>Type</th><th>Objet</th><th>Client</th><th>Opportunité</th><th>Statut</th></tr></thead><tbody>${rows.map(x=>`<tr><td>${datetime(x.scheduled_at||x.created_at)}</td><td>${esc(x.activity_type)}</td><td class="primary wrap">${esc(x.subject)}<small>${esc(x.description||'')}</small></td><td>${esc(clientName(clientFor(state,x.client_id)))}</td><td>${esc(opportunityFor(state,x.opportunity_id)?.name||'—')}</td><td>${statusBadge(x.completed_at?'completed':'pending')}</td></tr>`).join('')}</tbody></table>`:empty('Aucune activité','Ajoutez un appel, une tâche ou une note.',button('Ajouter','PilozModern.openActivity()','btn-p'))}</div>`;}
 function openReminder(documentId='',opportunityId=''){const state=app().getState(),docs=(state.data.documents||[]).filter(x=>['quote','invoice','deposit_invoice','balance_invoice'].includes(x.document_type)).map(x=>[x.id,`${x.number||typeLabels[x.document_type]} · ${clientName(clientFor(state,x.client_id))}`]),opportunities=(state.data.opportunities||[]).map(x=>[x.id,x.name]);showDrawer('Programmer une relance',`<form id="modern-reminder-form" class="modern-form" onsubmit="event.preventDefault();PilozModern.saveReminder()">${selectField('Type','reminder_type',[['commercial','Commerciale'],['payment','Paiement'],['quote','Devis'],['task','Tâche']],'commercial')}${field('Objet *','subject','','text','required')}${selectField('Document','document_id',[['','Aucun'],...docs],documentId)}${selectField('Opportunité','opportunity_id',[['','Aucune'],...opportunities],opportunityId)}${field('Date et heure *','due_at','','datetime-local','required')}<label class="modern-field full"><span>Message</span><textarea name="message"></textarea></label><div class="modern-form-actions">${button('Annuler','PilozModern.closeDrawer()')}${button('Programmer','', 'btn-p','type="submit"')}</div></form>`);}
 function newOpportunityDocument(opportunityId,type){const state=app().getState(),opportunity=opportunityFor(state,opportunityId);closeDrawer();app().newDocument(type);const draft=app().getState().draft;if(draft){draft.opportunity_id=opportunityId;draft.client_id=opportunity?.client_id||'';draft.assigned_user_id=opportunity?.assigned_user_id||global.PilozRuntime.session.user_id;}}
 async function uploadOpportunityAttachment(opportunityId,file){if(!file)return;if(file.size>10485760){notify('La pièce jointe dépasse 10 Mo.','error');return;}const state=app().getState(),extension=(file.name.split('.').pop()||'bin').replace(/[^a-z0-9]/gi,'').toLowerCase(),path=`${state.companyId}/opportunities/${opportunityId}/${Date.now()}-${uuid()}.${extension}`;try{await api().upload('company-files',path,file);await api().insert('attachments',{company_id:state.companyId,entity_type:'opportunity',entity_id:opportunityId,storage_path:path,file_name:file.name,mime_type:file.type||null,size_bytes:file.size});await app().refresh();openOpportunity(opportunityId);notify('Pièce jointe ajoutée.','success');}catch(error){notify(error.message,'error');}}
 async function saveReminder(){const data=Object.fromEntries(new FormData(document.getElementById('modern-reminder-form'))),state=app().getState(),doc=(state.data.documents||[]).find(x=>x.id===data.document_id),opportunity=opportunityFor(state,data.opportunity_id);data.company_id=state.companyId;data.document_id=data.document_id||null;data.opportunity_id=data.opportunity_id||null;data.client_id=doc?.client_id||opportunity?.client_id||null;data.due_at=new Date(data.due_at).toISOString();try{await api().insert('reminders',data);closeDrawer();await app().refresh();notify('Relance programmée.','success');}catch(error){notify(error.message,'error');}}
 async function completeReminder(id){try{await api().update('reminders',id,{status:'completed',completed_at:new Date().toISOString()});await app().refresh();notify('Relance terminée.','success');}catch(error){notify(error.message,'error');}}
 function renderReminders(state,commercialOnly=false){const rows=(state.data.reminders||[]).filter(x=>!commercialOnly||x.reminder_type==='commercial');document.getElementById('main').innerHTML=header(commercialOnly?'Relances commerciales':'Relances','Actions planifiées et échéances de suivi.',button('Programmer une relance','PilozModern.openReminder()','btn-p'))+`<div class="modern-table-shell">${rows.length?`<table class="modern-table"><thead><tr><th>Échéance</th><th>Type</th><th>Objet</th><th>Client</th><th>Document</th><th>Statut</th><th>Action</th></tr></thead><tbody>${rows.map(x=>{const doc=(state.data.documents||[]).find(d=>d.id===x.document_id);return`<tr><td>${datetime(x.due_at)}</td><td>${esc(x.reminder_type)}</td><td class="primary wrap">${esc(x.subject)}<small>${esc(x.message||'')}</small></td><td>${esc(clientName(clientFor(state,x.client_id||doc?.client_id)))}</td><td>${esc(doc?.number||'—')}</td><td>${statusBadge(x.status)}</td><td>${x.status==='pending'?button('Terminer',`PilozModern.completeReminder('${x.id}')`,'btn-ghost'):''}</td></tr>`;}).join('')}</tbody></table>`:empty('Aucune relance','Programmez une prochaine action utile.',button('Programmer','PilozModern.openReminder()','btn-p'))}</div>`;}
 function openProspect(){showDrawer('Nouveau prospect',`<form id="modern-prospect-form" class="modern-form" onsubmit="event.preventDefault();PilozModern.saveProspect()"><div class="modern-field full"><span>Type</span><select name="kind" onchange="PilozModern.toggleProspectKind(this.value)"><option value="company">Professionnel</option><option value="person">Particulier</option></select></div><div id="professional-fields" class="modern-form" style="display:contents"><label class="modern-field full"><span>Recherche officielle</span><input id="modern-company-search" placeholder="Raison sociale, SIREN ou SIRET" oninput="PilozModern.searchOfficialCompany(this.value)"><div id="modern-company-results"></div></label>${field('Raison sociale *','legal_name','','text','required')}${field('Nom commercial','trade_name')}${field('Forme juridique','legal_form')}${field('SIREN','siren')}${field('SIRET','siret')}${field('Code APE / NAF','ape_code')}</div><div id="person-fields" class="modern-form" style="display:none">${field('Civilité','civility')}${field('Prénom *','first_name')}${field('Nom *','last_name')}</div>${field('E-mail','email','','email')}${field('Téléphone','phone_e164','','tel')}<label class="modern-field full"><span>Recherche d’adresse</span><input placeholder="Commencez à saisir une adresse" oninput="PilozModern.searchProspectAddress(this.value)"><div id="modern-address-results"></div></label>${field('Adresse','address_line_1')}${field('Complément','address_line_2')}${field('Code postal','postal_code')}${field('Ville','city')}${field('Pays','country_code','FR')}<div class="modern-form-actions">${button('Annuler','PilozModern.closeDrawer()')}${button('Enregistrer','', 'btn-p','type="submit"')}</div></form>`);}
 function toggleProspectKind(kind){document.getElementById('professional-fields').style.display=kind==='company'?'contents':'none';document.getElementById('person-fields').style.display=kind==='person'?'contents':'none';const form=document.getElementById('modern-prospect-form');form.elements.legal_name.required=kind==='company';form.elements.first_name.required=kind==='person';form.elements.last_name.required=kind==='person';}
 let companyTimer,addressTimer,companyResults=[],addressResults=[];
 function searchOfficialCompany(value){clearTimeout(companyTimer);const query=value.trim();if(query.length<2){renderCompanyResults([]);return;}companyTimer=setTimeout(async()=>{try{const data=await api().invoke('company-search',{query,perPage:6});companyResults=data.results||[];renderCompanyResults(companyResults);}catch(error){notify(error.message,'error');}},280);}
 function renderCompanyResults(results){const node=document.getElementById('modern-company-results');if(node)node.innerHTML=results.map((x,index)=>`<button type="button" class="erp-row-button" onclick="PilozModern.selectOfficialCompany(${index})"><span><b>${esc(x.legalName||'Entreprise')}</b><small>${esc([x.siret,x.postalCode,x.city].filter(Boolean).join(' · '))}</small></span></button>`).join('');}
 function selectOfficialCompany(index){const x=companyResults[index],form=document.getElementById('modern-prospect-form');if(!x||!form)return;const map={legal_name:'legalName',trade_name:'tradeName',legal_form:'legalForm',siren:'siren',siret:'siret',ape_code:'apeCode',address_line_1:'addressLine1',postal_code:'postalCode',city:'city',country_code:'countryCode'};Object.entries(map).forEach(([fieldName,key])=>{if(x[key]!=null)form.elements[fieldName].value=x[key];});renderCompanyResults([]);}
 function searchProspectAddress(value){clearTimeout(addressTimer);const query=value.trim();if(query.length<3){renderAddressResults([]);return;}addressTimer=setTimeout(async()=>{try{const data=await api().invoke('address-search',{query});addressResults=data.results||[];renderAddressResults(addressResults);}catch(error){notify(error.message,'error');}},280);}
 function renderAddressResults(results){const node=document.getElementById('modern-address-results');if(node)node.innerHTML=results.map((x,index)=>`<button type="button" class="erp-row-button" onclick="PilozModern.selectProspectAddress(${index})"><span><b>${esc(x.label)}</b><small>${esc([x.postalCode,x.city].filter(Boolean).join(' '))}</small></span></button>`).join('');}
 function selectProspectAddress(index){const x=addressResults[index],form=document.getElementById('modern-prospect-form');if(!x||!form)return;const map={address_line_1:'addressLine1',address_line_2:'addressLine2',postal_code:'postalCode',city:'city',country_code:'countryCode'};Object.entries(map).forEach(([fieldName,key])=>form.elements[fieldName].value=x[key]||'');renderAddressResults([]);}
 async function saveProspect(){const form=document.getElementById('modern-prospect-form'),data=Object.fromEntries(new FormData(form)),state=app().getState();if(data.kind==='company'&&!data.legal_name.trim()){notify('La raison sociale est obligatoire.','error');return;}if(data.kind==='person'&&(!data.first_name.trim()||!data.last_name.trim())){notify('Le prénom et le nom sont obligatoires.','error');return;}data.company_id=state.companyId;data.relationship_type='prospect';try{await api().insert('clients',data);closeDrawer();await app().refresh();notify('Prospect enregistré.','success');}catch(error){notify(error.message,'error');}}
 function renderProspects(state){const rows=(state.data.clients||[]).filter(x=>x.relationship_type==='prospect');document.getElementById('main').innerHTML=header('Prospects','Particuliers et professionnels avant leur conversion en clients.',button('Nouveau prospect','PilozModern.openProspect()','btn-p'))+`<div class="modern-table-shell">${rows.length?`<table class="modern-table"><thead><tr><th>Prospect</th><th>Type</th><th>Coordonnées</th><th>Adresse</th><th>Création</th></tr></thead><tbody>${rows.map(x=>`<tr><td class="primary">${esc(clientName(x))}<small>${esc(x.siret||'')}</small></td><td>${x.kind==='person'?'Particulier':'Professionnel'}</td><td>${esc(x.email||'—')}<small>${esc(x.phone_e164||'')}</small></td><td>${esc([x.address_line_1,x.postal_code,x.city].filter(Boolean).join(', ')||'—')}</td><td>${date(x.created_at)}</td></tr>`).join('')}</tbody></table>`:empty('Aucun prospect','Ajoutez un particulier ou une entreprise à qualifier.',button('Ajouter','PilozModern.openProspect()','btn-p'))}</div>`;}

 function purchasesOverview(state){const orders=state.data.purchaseOrders||[],receipts=state.data.receipts||[],open=orders.filter(x=>!['received','cancelled'].includes(x.status)),expected=open.reduce((s,x)=>s+Number(x.total_incl_tax),0);document.getElementById('main').innerHTML=header('Achats','Fournisseurs, commandes, réceptions et factures fournisseurs.',button('Nouvelle commande','PilozApp.openPurchaseOrderForm()','btn-p'))+`<div class="modern-kpis">${kpi('Fournisseurs',(state.data.suppliers||[]).length)}${kpi('Commandes ouvertes',open.length)}${kpi('Montant commandé',money(expected))}${kpi('Réceptions',receipts.length)}</div><div class="erp-grid-2"><section class="phase1-card"><h2>Commandes à recevoir</h2>${open.slice(0,8).map(x=>`<button class="erp-row-button" onclick="PilozApp.go('purchases/orders')"><span><b>${esc(x.number||'Commande')}</b><small>${esc(x.supplier?.legal_name||'')}</small></span><strong>${money(x.total_incl_tax)}</strong></button>`).join('')||'<p>Aucune commande ouverte.</p>'}</section><section class="phase1-card"><h2>Dernières réceptions</h2>${receipts.slice(0,8).map(x=>`<div class="erp-row-button"><span><b>${esc(x.number||'Réception')}</b><small>${date(x.received_at||x.created_at)}</small></span>${statusBadge(x.status)}</div>`).join('')||'<p>Aucune réception.</p>'}</section></div>`;}
 function openSupplierInvoice(){const state=app().getState(),orders=(state.data.purchaseOrders||[]).filter(x=>['confirmed','partially_received','received'].includes(x.status));showDrawer('Créer une facture fournisseur',`<form id="supplier-invoice-form" class="modern-form" onsubmit="event.preventDefault();PilozModern.saveSupplierInvoice()">${selectField('Commande fournisseur *','purchase_order_id',orders.map(x=>[x.id,`${x.number||'Commande'} · ${x.supplier?.legal_name||''}`]),'','true')}${field('Date d’émission','issue_date',iso(new Date()),'date','required')}${field('Date d’échéance','due_date','','date')}${field('Référence fournisseur','client_reference')}<div class="modern-form-actions">${button('Annuler','PilozModern.closeDrawer()')}${button('Créer le brouillon','', 'btn-p','type="submit"')}</div></form>`);}
 async function saveSupplierInvoice(){const state=app().getState(),data=Object.fromEntries(new FormData(document.getElementById('supplier-invoice-form'))),order=(state.data.purchaseOrders||[]).find(x=>x.id===data.purchase_order_id),lines=(state.data.purchaseOrderLines||[]).filter(x=>x.purchase_order_id===data.purchase_order_id);if(!order){notify('Sélectionnez une commande fournisseur.','error');return;}try{const document=(await api().insert('documents',{company_id:state.companyId,document_type:'purchase_invoice',supplier_id:order.supplier_id,status:'draft',issue_date:data.issue_date,due_date:data.due_date||null,client_reference:data.client_reference||null,currency:order.currency||'EUR',subject:`Facture fournisseur ${order.number||''}`,source_document_id:null,total_cost:order.total_excl_tax,total_excl_tax:order.total_excl_tax,total_tax:order.total_tax,total_incl_tax:order.total_incl_tax}))[0];if(lines.length)await api().insert('document_lines',lines.map((line,index)=>{const item=(state.data.catalog||[]).find(x=>x.id===line.item_id),ht=Number(line.quantity)*Number(line.unit_price)*(1-Number(line.discount_rate||0)/100),tax=ht*Number(line.tax_rate||0)/100;return{company_id:state.companyId,document_id:document.id,position:index+1,line_type:'item',item_id:line.item_id,reference:item?.reference,name:item?.name,quantity:line.quantity,unit:item?.unit||'unité',unit_cost_snapshot:line.unit_price,unit_price:line.unit_price,discount_rate:line.discount_rate||0,tax_rate:line.tax_rate||0,total_excl_tax:ht,total_tax:tax,total_incl_tax:ht+tax};}));closeDrawer();await app().refresh();notify('Facture fournisseur créée.','success');}catch(error){notify(error.message,'error');}}
 function renderSupplierInvoices(state){const rows=(state.data.documents||[]).filter(x=>x.document_type==='purchase_invoice');document.getElementById('main').innerHTML=header('Factures fournisseurs','Factures d’achat reliées aux fournisseurs et aux commandes.',button('Créer depuis une commande','PilozModern.openSupplierInvoice()','btn-p'))+`<div class="modern-table-shell">${rows.length?`<table class="modern-table"><thead><tr><th>Référence</th><th>Fournisseur</th><th>Émission</th><th>Échéance</th><th>HT</th><th>TVA</th><th>TTC</th><th>Statut</th></tr></thead><tbody>${rows.map(x=>{const supplier=(state.data.suppliers||[]).find(s=>s.id===x.supplier_id);return`<tr><td class="primary">${esc(x.number||x.client_reference||'Brouillon')}</td><td>${esc(supplier?.legal_name||'—')}</td><td>${date(x.issue_date)}</td><td>${date(x.due_date)}</td><td class="money">${money(x.total_excl_tax)}</td><td class="money">${money(x.total_tax)}</td><td class="money primary">${money(x.total_incl_tax)}</td><td>${statusBadge(x.status)}</td></tr>`;}).join('')}</tbody></table>`:empty('Aucune facture fournisseur','Créez une facture depuis une commande confirmée.',button('Créer','PilozModern.openSupplierInvoice()','btn-p'))}</div>`;}

 function renderReports(state){const thisYear=new Date().getFullYear(),current=dashboardMetrics(state,{start:new Date(thisYear,0,1),end:new Date(thisYear+1,0,1)}),previous=dashboardMetrics(state,{start:new Date(thisYear-1,0,1),end:new Date(thisYear,0,1)}),clientMap=new Map();(state.data.documents||[]).filter(x=>['invoice','deposit_invoice','balance_invoice','credit_note'].includes(x.document_type)&&x.issue_date?.startsWith(String(thisYear))).forEach(x=>clientMap.set(x.client_id,(clientMap.get(x.client_id)||0)+invoiceSign(x)*Number(x.total_excl_tax)));document.getElementById('main').innerHTML=header('Rapports','Analyse des ventes, encaissements, marges et clients sur les vraies données.',button('Exporter les factures','PilozModern.exportDocuments()','btn-p'))+`<div class="modern-kpis">${kpi(`CA HT ${thisYear}`,money(current.revenue))}${kpi(`CA HT ${thisYear-1}`,money(previous.revenue))}${kpi('Marge brute',money(current.margin))}${kpi('Taux de marque',current.revenue?(current.margin/current.revenue*100).toFixed(1)+' %':'—')}</div><div class="erp-grid-2"><section class="phase1-card"><h2>Top clients ${thisYear}</h2>${ranked([...clientMap].map(([id,value])=>({label:clientName(clientFor(state,id)),value})).sort((a,b)=>b.value-a.value))}</section><section class="phase1-card"><h2>Encaissement</h2><div class="modern-widget-value">${money(current.payments)}</div><p>Encaissé sur l’année · reste global ${money(current.outstanding)}</p></section></div>`;}

 function renderVatSettings(state){const rates=state.data.vatRates||[];document.getElementById('main').innerHTML=header('Ventes & TVA','Les taux proposés dans les documents sont exclusivement ceux configurés ici.',button('Nouveau taux','PilozModern.openVatRate()','btn-p'))+`<div class="modern-table-shell">${rates.length?`<table class="modern-table"><thead><tr><th>Libellé</th><th>Taux</th><th>Compte comptable</th><th>Début</th><th>Fin</th><th>Défaut</th><th>Statut</th><th>Action</th></tr></thead><tbody>${rates.map(x=>`<tr><td class="primary">${esc(x.label)}</td><td>${Number(x.rate).toLocaleString('fr-FR')} %</td><td>${esc(x.account_code||'—')}</td><td>${date(x.valid_from)}</td><td>${date(x.valid_until)}</td><td>${x.is_default?'Oui':'Non'}</td><td>${statusBadge(x.active?'active':'archived')}</td><td>${button('Modifier',`PilozModern.openVatRate('${x.id}')`,'btn-ghost')}</td></tr>`).join('')}</tbody></table>`:empty('Aucun taux de TVA','Ajoutez les taux autorisés avant de créer des documents.',button('Ajouter','PilozModern.openVatRate()','btn-p'))}</div>`;}
 function openVatRate(id=''){const state=app().getState(),item=(state.data.vatRates||[]).find(x=>x.id===id)||{};showDrawer(id?'Modifier le taux':'Nouveau taux de TVA',`<form id="vat-form" class="modern-form" onsubmit="event.preventDefault();PilozModern.saveVatRate('${id}')">${field('Libellé *','label',item.label,'text','required')}${field('Taux (%) *','rate',item.rate??20,'number','min="0" max="100" step="0.01" required')}${field('Compte comptable','account_code',item.account_code)}${field('Date de début','valid_from',item.valid_from,'date')}${field('Date de fin','valid_until',item.valid_until,'date')}<label class="modern-field"><span>Par défaut</span><select name="is_default"><option value="false">Non</option><option value="true" ${item.is_default?'selected':''}>Oui</option></select></label><label class="modern-field"><span>Actif</span><select name="active"><option value="true">Oui</option><option value="false" ${item.active===false?'selected':''}>Non</option></select></label><div class="modern-form-actions">${button('Annuler','PilozModern.closeDrawer()')}${button('Enregistrer','', 'btn-p','type="submit"')}</div></form>`);}
 async function saveVatRate(id){const state=app().getState(),data=Object.fromEntries(new FormData(document.getElementById('vat-form')));data.company_id=state.companyId;data.rate=Number(data.rate);data.is_default=data.is_default==='true';data.active=data.active==='true';data.valid_from=data.valid_from||null;data.valid_until=data.valid_until||null;try{if(data.is_default)await Promise.all((state.data.vatRates||[]).filter(x=>x.is_default&&x.id!==id).map(x=>api().update('vat_rates',x.id,{is_default:false})));id?await api().update('vat_rates',id,data):await api().insert('vat_rates',data);closeDrawer();await app().refresh();notify('Taux de TVA enregistré.','success');}catch(error){notify(error.message,'error');}}
 function renderPipelineSettings(state){const stages=state.data.pipelineStages||[],automations=state.data.erpSettings?.[0]?.crm_automations||{};document.getElementById('main').innerHTML=header('Pipeline & automatisations','Étapes, probabilités et changements déclenchés par les documents.',button('Nouvelle étape','PilozModern.openPipelineStage()','btn-p'))+`<div class="erp-grid-2"><section class="phase1-card"><h2>Étapes du pipeline</h2>${stages.map(x=>`<button class="erp-row-button" onclick="PilozModern.openPipelineStage('${x.id}')"><span><b>${esc(x.name)}</b><small>${Number(x.probability)} % · position ${x.position}</small></span><span style="width:12px;height:12px;border-radius:50%;background:${esc(x.color)}"></span></button>`).join('')||'<p>Aucune étape configurée.</p>'}</section><section class="phase1-card"><h2>Automatisations</h2>${[['quote_created','Devis créé → Devis en préparation'],['quote_sent','Devis envoyé → Devis envoyé'],['quote_accepted','Devis accepté → Opportunité gagnée'],['quote_rejected','Devis refusé → Opportunité perdue'],['invoice_created','Facture créée → Facturation'],['invoice_paid','Facture payée → Encaissé']].map(([key,label])=>`<label class="phase1-check"><input type="checkbox" ${automations[key]!==false?'checked':''} onchange="PilozModern.saveAutomation('${key}',this.checked)"><span>${esc(label)}</span></label>`).join('')}</section></div>`;}
 function openPipelineStage(id=''){const state=app().getState(),item=(state.data.pipelineStages||[]).find(x=>x.id===id)||{},position=item.position??(((state.data.pipelineStages||[]).at(-1)?.position||0)+10);showDrawer(id?'Modifier l’étape':'Nouvelle étape',`<form id="pipeline-stage-form" class="modern-form" onsubmit="event.preventDefault();PilozModern.savePipelineStage('${id}')">${field('Nom *','name',item.name,'text','required',true)}${field('Identifiant *','slug',item.slug,'text',id?'readonly':'required')}${field('Position','position',position,'number','min="0" step="1"')}${field('Probabilité (%)','probability',item.probability??0,'number','min="0" max="100" step="0.01"')}${field('Couleur','color',item.color||'#52606d','color')}<label class="modern-field"><span>Issue gagnée</span><select name="is_won"><option value="false">Non</option><option value="true" ${item.is_won?'selected':''}>Oui</option></select></label><label class="modern-field"><span>Issue perdue</span><select name="is_lost"><option value="false">Non</option><option value="true" ${item.is_lost?'selected':''}>Oui</option></select></label><div class="modern-form-actions">${button('Annuler','PilozModern.closeDrawer()')}${button('Enregistrer','', 'btn-p','type="submit"')}</div></form>`);}
 async function savePipelineStage(id){const state=app().getState(),data=Object.fromEntries(new FormData(document.getElementById('pipeline-stage-form')));data.company_id=state.companyId;data.slug=String(data.slug||data.name).trim().toLocaleLowerCase('fr').normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^a-z0-9]+/g,'_').replace(/^_|_$/g,'');data.position=Number(data.position)||0;data.probability=Number(data.probability)||0;data.is_won=data.is_won==='true';data.is_lost=data.is_lost==='true';if(data.is_won&&data.is_lost){notify('Une étape ne peut pas être gagnée et perdue à la fois.','error');return;}try{id?await api().update('pipeline_stages',id,data):await api().insert('pipeline_stages',data);closeDrawer();await app().refresh();notify('Étape du pipeline enregistrée.','success');}catch(error){notify(error.message,'error');}}
 async function saveAutomation(key,value){const state=app().getState(),current=state.data.erpSettings?.[0]||{},crm_automations={...(current.crm_automations||{}),[key]:value};try{await api().request('/rest/v1/company_erp_settings?on_conflict=company_id',{method:'POST',headers:{Prefer:'resolution=merge-duplicates,return=minimal'},body:JSON.stringify({company_id:state.companyId,crm_automations})});await app().refresh();notify('Automatisation enregistrée.','success');}catch(error){notify(error.message,'error');}}

 const filled=value=>value!==null&&value!==undefined&&String(value).trim()!=='';
 const dash=(value,formatter)=>filled(value)?(formatter?formatter(value):esc(value)):'—';
 function maskIban(iban){const clean=String(iban).replace(/\s+/g,'');return clean.length>4?'•••• '+clean.slice(-4):clean;}
 const companySubNavItems=[
  ['profile','Identité','👤','Raison sociale, forme juridique, activité'],
  ['contacts','Coordonnées','✉️','E-mail, téléphone, contact principal'],
  ['addresses','Adresses','📍','Siège, facturation, livraison'],
  ['legal','Informations légales','🧾','SIREN, SIRET, RCS, capital social'],
  ['tax','Fiscalité','💶','TVA, devise, exercice comptable'],
  ['logo','Logo','🖼️','Logo clair, logo sombre et aperçu'],
  ['bank','Coordonnées bancaires','🏦','IBAN, BIC, moyens de paiement']
 ];
 function companySubNav(active){return`<nav class="company-subnav">${companySubNavItems.map(([key,label,icon,desc])=>`<button type="button" class="company-subnav-item ${active===key?'active':''}" onclick="PilozApp.go('settings/company${key?'/'+key:''}')"><span class="icon">${icon}</span><span class="label"><b>${esc(label)}</b><small>${esc(desc)}</small></span><span class="chevron">›</span></button>`).join('')}</nav>`;}
 function companyShell(active,title,description,bodyHtml){document.getElementById('main').innerHTML=header(title,description)+`<div class="company-layout">${companySubNav(active)}<div>${bodyHtml}</div></div>`;}

 function renderCompanyOverview(state){
  const s=state.data.settings?.[0]||{},docs=state.data.docSettings?.[0]||{},addr=(state.data.addresses||[]).find(x=>x.kind==='registered')||{};
  const registeredAddress=[addr.address_line_1,[addr.postal_code,addr.city].filter(Boolean).join(' ')].filter(Boolean).join(', ');
  const body=`<div class="company-summary-grid">
   <section class="company-summary-card"><h3>Profil de l’entreprise</h3><dl>
    <div><dt>Raison sociale</dt><dd>${dash(s.legal_name)}</dd></div>
    <div><dt>Nom commercial</dt><dd>${dash(s.trade_name)}</dd></div>
    <div><dt>Forme juridique</dt><dd>${dash(s.legal_form)}</dd></div>
   </dl><div class="actions">${button('Modifier',`PilozApp.go('settings/company/profile')`,'btn-o')}</div></section>
   <section class="company-summary-card"><h3>Coordonnées</h3><dl>
    <div><dt>E-mail</dt><dd>${dash(s.email)}</dd></div>
    <div><dt>Téléphone</dt><dd>${dash(s.phone||s.phone_e164)}</dd></div>
    <div><dt>Site internet</dt><dd>${dash(s.website)}</dd></div>
   </dl><div class="actions">${button('Modifier',`PilozApp.go('settings/company/contacts')`,'btn-o')}</div></section>
   <section class="company-summary-card"><h3>Adresse principale</h3><dl>
    <div><dt>Adresse</dt><dd>${dash(registeredAddress||null)}</dd></div>
   </dl><div class="actions">${button('Modifier',`PilozApp.go('settings/company/addresses')`,'btn-o')}</div></section>
   <section class="company-summary-card"><h3>Informations légales</h3><dl>
    <div><dt>SIREN</dt><dd>${dash(s.siren)}</dd></div>
    <div><dt>SIRET</dt><dd>${dash(s.siret)}</dd></div>
    <div><dt>Code APE</dt><dd>${dash(s.ape_code)}</dd></div>
   </dl><div class="actions">${button('Modifier',`PilozApp.go('settings/company/legal')`,'btn-o')}</div></section>
   <section class="company-summary-card"><h3>Fiscalité</h3><dl>
    <div><dt>Assujettie à la TVA</dt><dd>${s.subject_to_vat===true?'Oui':s.subject_to_vat===false?'Non':'—'}</dd></div>
    <div><dt>N° TVA</dt><dd>${dash(s.vat_number)}</dd></div>
    <div><dt>Devise</dt><dd>${dash(s.currency)}</dd></div>
   </dl><div class="actions">${button('Modifier',`PilozApp.go('settings/company/tax')`,'btn-o')}</div></section>
   <section class="company-summary-card"><h3>Banque</h3><dl>
    <div><dt>Titulaire</dt><dd>${dash(docs.bank_account_holder)}</dd></div>
    <div><dt>IBAN</dt><dd>${docs.iban?maskIban(docs.iban):'—'}</dd></div>
   </dl><div class="actions">${button('Modifier',`PilozApp.go('settings/company/bank')`,'btn-o')}</div></section>
  </div>`;
  companyShell('','Mon entreprise','Vue d’ensemble de votre profil, vos coordonnées et vos informations légales.',body);
 }

 function isSchemaSyncError(error){return['PGRST204','42703'].includes(String(error?.code||''))||/column .* does not exist|schema cache/i.test(String(error?.message||''));}
 async function saveWithFallback(companyId,data,extendedKeys,label){
  try{await api().upsertCompanySettings(companyId,data);await app().refresh();notify(`${label} enregistré(e)s.`,'success');return true;}
  catch(error){
   if(!isSchemaSyncError(error)){notify(error.message,'error');return false;}
   const core=Object.fromEntries(Object.entries(data).filter(([key])=>!extendedKeys.includes(key)));
   try{await api().upsertCompanySettings(companyId,core);await app().refresh();notify(`${label} enregistré(e)s partiellement : certains champs seront actifs après une prochaine mise à jour de la base.`,'info');return true;}
   catch(error2){notify(error2.message,'error');return false;}
  }
 }
 function renderCompanyProfile(state){const s=state.data.settings?.[0]||{};const body=`<section class="phase1-card"><h2>Identité de l’entreprise</h2><form id="company-profile-form" class="modern-form" onsubmit="event.preventDefault();PilozModern.saveCompanyProfile()">${field('Raison sociale *','legal_name',s.legal_name,'text','required')}${field('Nom commercial','trade_name',s.trade_name)}${selectField('Forme juridique *','legal_form',LEGAL_FORM_OPTIONS,s.legal_form)}${selectField('Type d’entreprise','company_type',COMPANY_TYPE_OPTIONS,s.company_type)}${field('Date de création','creation_date',s.creation_date,'date')}${field('Activité principale','activity',s.activity)}${field('Site internet','website',s.website,'url')}<label class="modern-field full"><span>Description</span><textarea name="description">${esc(s.description||'')}</textarea></label><div class="modern-form-actions">${button('Annuler',`PilozApp.go('settings/company')`,'btn-ghost')}${button('Enregistrer','','btn-p','type="submit"')}</div></form></section>`;companyShell('profile','Identité','Identité générale de votre entreprise.',body);}
 async function saveCompanyProfile(){const state=app().getState(),data=Object.fromEntries(new FormData(document.getElementById('company-profile-form')));data.creation_date=data.creation_date||null;await saveWithFallback(state.companyId,data,['company_type','description'],'Le profil');}

 function renderCompanyContacts(state){const s=state.data.settings?.[0]||{};const body=`<section class="phase1-card"><h2>Coordonnées</h2><form id="company-contacts-form" class="modern-form" onsubmit="event.preventDefault();PilozModern.saveCompanyContacts()">${field('E-mail professionnel *','email',s.email,'email','required')}${field('Téléphone principal','phone',s.phone||s.phone_e164,'tel')}${field('Téléphone secondaire','secondary_phone',s.secondary_phone,'tel')}${field('Contact principal','primary_contact_name',s.primary_contact_name)}<div class="modern-field full">${s.email_confirmed_at?`<span class="modern-status success">E-mail confirmé le ${date(s.email_confirmed_at)}</span>`:`<span class="modern-status warning">E-mail non confirmé</span> ${button('Envoyer la confirmation','PilozModern.requestCompanyEmailConfirmation()','btn-ghost','type="button"')}`}</div><div class="modern-field full">${s.phone_verified_at?`<span class="modern-status success">Téléphone vérifié</span>`:`<span class="modern-status warning">Téléphone non vérifié</span> ${button('Vérifier par SMS','PilozModern.requestCompanyPhoneVerification()','btn-ghost','type="button"')}`}</div><div class="modern-form-actions">${button('Annuler',`PilozApp.go('settings/company')`,'btn-ghost')}${button('Enregistrer','','btn-p','type="submit"')}</div></form></section>`;companyShell('contacts','Coordonnées','Comment vos clients et Piloz peuvent vous contacter.',body);}
 async function saveCompanyContacts(){const state=app().getState(),data=Object.fromEntries(new FormData(document.getElementById('company-contacts-form')));await saveWithFallback(state.companyId,data,['secondary_phone','primary_contact_name'],'Les coordonnées');}
 async function requestCompanyEmailConfirmation(){const state=app().getState(),email=document.querySelector('#company-contacts-form [name="email"]')?.value;if(!email){notify('Renseignez un e-mail.','error');return;}try{await api().invoke('request-company-email-confirmation',{companyId:state.companyId,email});notify('E-mail de confirmation envoyé.','success');}catch(error){notify(error.message,'error');}}
 async function requestCompanyPhoneVerification(){const state=app().getState(),raw=document.querySelector('#company-contacts-form [name="phone"]')?.value,phone=global.PilozCalculations.e164(raw,'FR');if(!phone){notify('Numéro de téléphone invalide.','error');return;}try{await api().invoke('request-company-phone-verification',{companyId:state.companyId,phone});showDrawer('Code de vérification',`<form id="company-phone-code-form" class="modern-form" onsubmit="event.preventDefault();PilozModern.confirmCompanyPhone()">${field('Code reçu par SMS','code','','text','inputmode="numeric" maxlength="6" required')}<div class="modern-form-actions">${button('Annuler','PilozModern.closeDrawer()')}${button('Confirmer','','btn-p','type="submit"')}</div></form>`);}catch(error){notify(error.message,'error');}}
 async function confirmCompanyPhone(){const state=app().getState(),code=new FormData(document.getElementById('company-phone-code-form')).get('code');try{await api().invoke('confirm-company-phone',{companyId:state.companyId,code});closeDrawer();await app().refresh();notify('Téléphone confirmé.','success');}catch(error){notify(error.message,'error');}}

 function addressCard(kind,label,addr,isRegistered){return`<section class="phase1-card"><h2>${esc(label)}</h2>${isRegistered?`<div class="modern-field full"><span>Recherche prédictive</span><input id="company-address-search" placeholder="Commencez à saisir une adresse" oninput="PilozModern.companyAddressSearch(this.value)"><div id="company-address-results" class="phase1-search-results"></div></div>`:''}<form id="company-address-${kind}-form" class="modern-form" onsubmit="event.preventDefault();PilozModern.saveCompanyAddress('${kind}')">${field('Adresse','address_line_1',addr.address_line_1)}${field('Complément','address_line_2',addr.address_line_2)}${field('Code postal','postal_code',addr.postal_code)}${field('Ville','city',addr.city)}${field('Pays','country_code',addr.country_code||'FR')}${!isRegistered?`<label class="modern-field"><span>Adresse par défaut</span><select name="is_primary"><option value="false" ${!addr.is_primary?'selected':''}>Non</option><option value="true" ${addr.is_primary?'selected':''}>Oui</option></select></label>`:''}<div class="modern-form-actions">${!isRegistered?button('Copier l’adresse du siège',`PilozModern.copyRegisteredAddress('${kind}')`,'btn-ghost','type="button"'):''}${button('Enregistrer','','btn-p','type="submit"')}</div></form></section>`;}
 function renderCompanyAddresses(state){const addresses=state.data.addresses||[],get=kind=>addresses.find(x=>x.kind===kind)||{};const body=addressCard('registered','Adresse du siège',get('registered'),true)+addressCard('billing','Adresse de facturation',get('billing'),false)+addressCard('shipping','Adresse de livraison',get('shipping'),false);companyShell('addresses','Adresses','Siège social, facturation et livraison.',body);}
 let companyAddressTimer=null,companyAddressResults=[];
 function companyAddressSearch(value){clearTimeout(companyAddressTimer);const q=value.trim();if(q.length<3)return;companyAddressTimer=setTimeout(async()=>{try{const data=await api().invoke('address-search',{query:q});companyAddressResults=data.results||[];const node=document.getElementById('company-address-results');if(node)node.innerHTML=companyAddressResults.map((x,i)=>`<button type="button" onclick="PilozModern.selectCompanyAddress(${i})"><b>${esc(x.label)}</b><small>${esc([x.postalCode,x.city].filter(Boolean).join(' '))}</small></button>`).join('')||'<p>Aucune adresse trouvée.</p>';}catch(error){notify(error.message,'error');}},300);}
 function selectCompanyAddress(index){const x=companyAddressResults[index];if(!x)return;const form=document.getElementById('company-address-registered-form');if(!form)return;form.elements.address_line_1.value=x.addressLine1||'';form.elements.address_line_2.value=x.addressLine2||'';form.elements.postal_code.value=x.postalCode||'';form.elements.city.value=x.city||'';const node=document.getElementById('company-address-results');if(node)node.innerHTML='';}
 function copyRegisteredAddress(targetKind){const state=app().getState(),reg=(state.data.addresses||[]).find(x=>x.kind==='registered')||{},form=document.getElementById(`company-address-${targetKind}-form`);if(!form)return;form.elements.address_line_1.value=reg.address_line_1||'';form.elements.address_line_2.value=reg.address_line_2||'';form.elements.postal_code.value=reg.postal_code||'';form.elements.city.value=reg.city||'';form.elements.country_code.value=reg.country_code||'FR';}
 async function saveCompanyAddress(kind){const state=app().getState(),form=document.getElementById(`company-address-${kind}-form`),data=Object.fromEntries(new FormData(form));data.is_primary=kind==='registered'?true:data.is_primary==='true';data.company_id=state.companyId;data.kind=kind;try{const existing=(state.data.addresses||[]).find(x=>x.kind===kind);if(existing)await api().update('company_addresses',existing.id,data);else await api().insert('company_addresses',data);await app().refresh();notify('Adresse enregistrée.','success');}catch(error){notify(error.message,'error');}}

 function renderCompanyLegal(state){const s=state.data.settings?.[0]||{};const body=`<section class="phase1-card"><h2>Informations légales</h2><form id="company-legal-form" class="modern-form" onsubmit="event.preventDefault();PilozModern.saveCompanyLegal()">${field('SIREN','siren',s.siren)}${field('SIRET','siret',s.siret)}${field('Code APE / NAF','ape_code',s.ape_code)}${field('N° TVA intracommunautaire','vat_number',s.vat_number)}${field('Numéro RCS','rcs_number',s.rcs_number)}${field('Ville du greffe','registry_court',s.registry_court)}${field('Capital social (€)','social_capital',s.social_capital,'number','min="0" step="0.01"')}<label class="modern-field full"><span>Mentions légales complémentaires</span><textarea name="legal_mentions">${esc(s.legal_mentions||'')}</textarea></label><div class="modern-form-actions">${button('Annuler',`PilozApp.go('settings/company')`,'btn-ghost')}${button('Enregistrer','','btn-p','type="submit"')}</div></form></section>`;companyShell('legal','Informations légales','Identifiants officiels de votre entreprise.',body);}
 async function saveCompanyLegal(){const state=app().getState(),data=Object.fromEntries(new FormData(document.getElementById('company-legal-form')));data.social_capital=data.social_capital===''?null:Number(data.social_capital);await saveWithFallback(state.companyId,data,['rcs_number','registry_court','social_capital','legal_mentions'],'Les informations légales');}

 function renderCompanyTax(state){const s=state.data.settings?.[0]||{},docs=state.data.docSettings?.[0]||{},rates=state.data.vatRates||[];const body=`<section class="phase1-card"><h2>Fiscalité</h2><form id="company-tax-form" class="modern-form" onsubmit="event.preventDefault();PilozModern.saveCompanyTax()"><label class="modern-field"><span>Assujettie à la TVA</span><select name="subject_to_vat"><option value="false" ${s.subject_to_vat===false?'selected':''}>Non</option><option value="true" ${s.subject_to_vat?'selected':''}>Oui</option></select></label>${selectField('Régime de TVA','vat_regime',VAT_REGIME_OPTIONS,s.vat_regime)}${selectField('Fréquence de déclaration','vat_frequency',VAT_FREQUENCY_OPTIONS,s.vat_frequency)}<label class="modern-field"><span>Taux de TVA par défaut</span><select name="default_vat_rate">${rates.length?rates.map(r=>`<option value="${r.rate}" ${Number(s.default_vat_rate)===Number(r.rate)?'selected':''}>${esc(r.label)} · ${Number(r.rate).toLocaleString('fr-FR')} %</option>`).join(''):`<option value="${s.default_vat_rate??20}">${s.default_vat_rate??20} %</option>`}</select></label>${selectField('Devise','currency',CURRENCY_OPTIONS,s.currency||'EUR')}${field('Début de l’exercice comptable (MM-JJ)','fiscal_year_start',s.fiscal_year_start||'01-01')}${selectField('Franchise en base','vat_franchise',[['','Choisir…'],['Oui','Oui'],['Non','Non']],s.vat_franchise)}${field('Mention de TVA par défaut','visible_mention',docs.visible_mention)}<div class="modern-form-actions">${button('Annuler',`PilozApp.go('settings/company')`,'btn-ghost')}${button('Enregistrer','','btn-p','type="submit"')}</div></form></section>`;companyShell('tax','Fiscalité','Régime de TVA et paramètres comptables.',body);}
 async function saveCompanyTax(){
  const state=app().getState(),form=document.getElementById('company-tax-form'),data=Object.fromEntries(new FormData(form));
  const visibleMention=data.visible_mention;delete data.visible_mention;
  data.subject_to_vat=data.subject_to_vat==='true';data.default_vat_rate=Number(data.default_vat_rate)||0;
  const ok=await saveWithFallback(state.companyId,data,['vat_frequency','fiscal_year_start','vat_franchise'],'La fiscalité');
  if(!ok)return;
  try{await api().request('/rest/v1/company_document_settings?on_conflict=company_id',{method:'POST',headers:{Prefer:'resolution=merge-duplicates,return=minimal'},body:JSON.stringify({company_id:state.companyId,visible_mention:visibleMention||null})});await app().refresh();}catch(error){notify(error.message,'error');}
 }


 function renderCompanyLogo(state){
  const logos=state.data.logos||[],urls=state.data.logoUrls||{};
  const card=(variant,label,help)=>{const logo=logos.find(row=>row.variant===variant&&row.is_active!==false),url=urls[variant];return`<section class="phase1-card company-logo-card"><div><h2>${esc(label)}</h2><p class="modern-card-desc">${esc(help)}</p></div><div class="company-logo-preview ${url?'has-logo':''}">${url?`<img src="${esc(url)}" alt="Aperçu du ${esc(label.toLowerCase())}">`:`<span>Aucun logo actif</span>`}</div><div class="company-logo-actions">${button(url?'Remplacer':'Ajouter',`document.getElementById('company-logo-${variant}').click()`,'btn-o','type="button"')}${logo?button('Supprimer',`PilozModern.removeCompanyLogo('${logo.id}','${esc(logo.storage_path)}')`,'btn-ghost','type="button"'):''}</div><input id="company-logo-${variant}" type="file" accept="image/png,image/jpeg,image/svg+xml" hidden onchange="PilozModern.uploadCompanyLogo(this.files[0],'${variant}');this.value=''" /></section>`;};
  const body=`<div class="company-logo-grid">${card('light','Logo clair','Utilisé sur les documents et les fonds clairs.')}${card('dark','Logo sombre','Facultatif, utilisé lorsque le fond exige une version contrastée.')}</div><section class="phase1-card"><h2>Formats acceptés</h2><p class="modern-card-desc">PNG, JPEG ou SVG sécurisé, 5 Mo maximum. Les fichiers sont stockés dans Supabase Storage et isolés par entreprise.</p></section>`;
  companyShell('logo','Logo','Ajoutez, remplacez ou supprimez les logos utilisés sur vos documents.',body);
 }
 async function uploadCompanyLogo(file,variant){if(!file)return;await app().uploadLogo(file,variant);await app().refresh();}
 async function removeCompanyLogo(id,path){await app().removeLogo(id,path);}

 function renderCompanyBank(state){const docs=state.data.docSettings?.[0]||{};const body=`<section class="phase1-card"><h2>Coordonnées bancaires</h2><form id="company-bank-form" class="modern-form" onsubmit="event.preventDefault();PilozModern.saveCompanyBank()">${field('Titulaire du compte','bank_account_holder',docs.bank_account_holder)}${field('Banque','bank_name',docs.bank_name)}<label class="modern-field"><span>IBAN</span><input name="iban" class="iban-mask" type="text" value="${esc(docs.iban?maskIban(docs.iban):'')}" data-full="${esc(docs.iban||'')}" onfocus="PilozModern.revealIban(this)" placeholder="FR76 ..."></label>${field('BIC','bic',docs.bic)}${field('Référence de mandat','mandate_reference',docs.mandate_reference)}<div class="modern-field full"><span>Moyens de paiement acceptés</span><div class="phase1-checks">${(phase1PaymentMethods||['Virement bancaire']).map(method=>`<label class="phase1-check"><input type="checkbox" name="accepted_payment_methods" value="${esc(method)}" ${(docs.accepted_payment_methods||[]).includes(method)?'checked':''}><span>${esc(method)}</span></label>`).join('')}</div></div><div class="modern-form-actions">${button('Annuler',`PilozApp.go('settings/company')`,'btn-ghost')}${button('Enregistrer','','btn-p','type="submit"')}</div></form></section>`;companyShell('bank','Coordonnées bancaires','Utilisées pour vos factures et prélèvements.',body);}
 function revealIban(input){if(input.dataset.full)input.value=input.dataset.full;}
 async function saveCompanyBank(){const state=app().getState(),form=document.getElementById('company-bank-form'),fd=new FormData(form),data=Object.fromEntries(fd);data.company_id=state.companyId;data.iban=String(data.iban||'').replace(/\s+/g,'').toUpperCase()||null;data.bic=String(data.bic||'').replace(/\s+/g,'').toUpperCase()||null;data.accepted_payment_methods=fd.getAll('accepted_payment_methods');try{await api().request('/rest/v1/company_document_settings?on_conflict=company_id',{method:'POST',headers:{Prefer:'resolution=merge-duplicates,return=minimal'},body:JSON.stringify(data)});await app().refresh();notify('Coordonnées bancaires enregistrées.','success');}catch(error){notify(error.message,'error');}}

 function renderSalesSettings(state){const docs=state.data.docSettings?.[0]||{},settings=state.data.settings?.[0]||{},rates=state.data.vatRates||[];document.getElementById('main').innerHTML=header('Ventes & TVA','Numérotation, paiements et taux de TVA utilisés dans vos devis et factures.')+`<div class="modern-settings-grid"><section class="phase1-card"><h2>Numérotation</h2><p class="modern-card-desc">Préfixes utilisés pour l’attribution automatique des numéros.</p><form id="sales-numbering-form" class="modern-form" onsubmit="event.preventDefault();PilozModern.saveSalesNumbering()">${field('Préfixe devis','quote_prefix',docs.quote_prefix||'DEV')}${field('Préfixe factures','invoice_prefix',docs.invoice_prefix||'FAC')}${field('Préfixe avoirs','credit_prefix',docs.credit_prefix||'AV')}${field('Validité des devis (jours)','quote_validity_days',docs.quote_validity_days||30,'number','min="1"')}<div class="modern-form-actions">${button('Enregistrer','','btn-p','type="submit"')}</div></form></section><section class="phase1-card"><h2>Paiements & conditions</h2><p class="modern-card-desc">Proposés par défaut sur vos nouveaux documents. Les coordonnées bancaires se renseignent dans Mon entreprise.</p><form id="sales-payment-form" class="modern-form" onsubmit="event.preventDefault();PilozModern.saveSalesPayment()">${selectField('Conditions de paiement','default_payment_terms',pairs(phase1PaymentTerms||['30 jours']),docs.default_payment_terms||'30 jours')}${selectField('Mode de paiement par défaut','default_payment_method',pairs(phase1PaymentMethods||['Virement bancaire']),docs.default_payment_method||'Virement bancaire')}<div class="modern-form-actions">${button('Enregistrer','','btn-p','type="submit"')}</div></form></section><section class="phase1-card"><h2>Devise</h2><p class="modern-card-desc">L’assujettissement et le numéro de TVA se gèrent dans Mon entreprise → Fiscalité.</p><form id="sales-tax-form" class="modern-form" onsubmit="event.preventDefault();PilozModern.saveSalesTax()">${selectField('Devise','currency',CURRENCY_OPTIONS,settings.currency||'EUR')}<div class="modern-form-actions">${button('Enregistrer','','btn-p','type="submit"')}</div></form></section><section class="phase1-card"><h2>Taux de TVA</h2><p class="modern-card-desc">Taux proposés dans l’éditeur de documents.</p>${button('Nouveau taux','PilozModern.openVatRate()','btn-p')}<div class="modern-table-shell">${rates.length?`<table class="modern-table"><thead><tr><th>Libellé</th><th>Taux</th><th>Défaut</th><th>Statut</th><th></th></tr></thead><tbody>${rates.map(x=>`<tr><td class="primary">${esc(x.label)}</td><td>${Number(x.rate).toLocaleString('fr-FR')} %</td><td>${x.is_default?'Oui':'Non'}</td><td>${statusBadge(x.active?'active':'archived')}</td><td>${button('Modifier',`PilozModern.openVatRate('${x.id}')`,'btn-ghost')}</td></tr>`).join('')}</tbody></table>`:empty('Aucun taux de TVA','Ajoutez les taux autorisés avant de créer des documents.')}</div></section></div>`;}
 async function saveSalesNumbering(){const state=app().getState(),data=Object.fromEntries(new FormData(document.getElementById('sales-numbering-form')));data.company_id=state.companyId;data.quote_validity_days=Number(data.quote_validity_days)||30;try{await api().request('/rest/v1/company_document_settings?on_conflict=company_id',{method:'POST',headers:{Prefer:'resolution=merge-duplicates,return=minimal'},body:JSON.stringify(data)});await app().refresh();notify('Numérotation enregistrée.','success');}catch(error){notify(error.message,'error');}}
 async function saveSalesPayment(){const state=app().getState(),data=Object.fromEntries(new FormData(document.getElementById('sales-payment-form')));data.company_id=state.companyId;try{await api().request('/rest/v1/company_document_settings?on_conflict=company_id',{method:'POST',headers:{Prefer:'resolution=merge-duplicates,return=minimal'},body:JSON.stringify(data)});await app().refresh();notify('Paiements enregistrés.','success');}catch(error){notify(error.message,'error');}}
 const builtinPaymentMethods=[['bank_transfer','Virement bancaire'],['direct_debit','Prélèvement'],['card','Carte'],['cheque','Chèque'],['cash','Espèces'],['paypal','PayPal'],['other','Autre']];
 const builtinPaymentTerms=[['cash','Comptant',0,'days'],['receipt','À réception',0,'receipt'],['days_7','7 jours',7,'days'],['days_15','15 jours',15,'days'],['days_30','30 jours',30,'days'],['days_45','45 jours',45,'days'],['days_60','60 jours',60,'days'],['end_of_month','Fin de mois',0,'end_of_month'],['days_30_end_of_month','30 jours fin de mois',30,'days_end_of_month']];
 function configuredMethods(state){const rows=state.data.paymentMethods||[];if(rows.length)return rows;const accepted=state.data.docSettings?.[0]?.accepted_payment_methods||[];return builtinPaymentMethods.map(([code,label],index)=>({code,label,active:!accepted.length||accepted.includes(label),is_default:[code,label].includes(state.data.docSettings?.[0]?.default_payment_method),position:(index+1)*10,details:'',is_custom:false}));}
 function configuredTerms(state){const rows=state.data.paymentTerms||[];if(rows.length)return rows;return builtinPaymentTerms.map(([code,label,days,calculation_rule],index)=>({code,label,days,calculation_rule,active:true,is_default:[code,label].includes(state.data.docSettings?.[0]?.default_payment_terms)||(code==='days_30'&&!state.data.docSettings?.[0]?.default_payment_terms),position:(index+1)*10,details:'',is_custom:false}));}
 function paymentConfiguration(state){const methods=configuredMethods(state),terms=configuredTerms(state);return`<section class="phase1-card sales-payment-settings"><header><div><h2>Paiements et échéances</h2><p class="modern-card-desc">Seuls les choix actifs sont proposés dans les devis et factures.</p></div>${button('Ajouter un délai personnalisé','PilozModern.openCustomPaymentTerm()','btn-o')}</header><form id="sales-payment-config-form" class="payment-config-form" onsubmit="event.preventDefault();PilozModern.savePaymentConfiguration()"><h3>Modes de paiement</h3><div class="payment-config-table"><div class="payment-config-head"><span>Actif</span><span>Par défaut</span><span>Mode</span><span>Ordre</span><span>Informations complémentaires</span><span></span></div>${methods.map(row=>`<div class="payment-config-row" data-payment-method data-id="${esc(row.id||'')}" data-code="${esc(row.code)}" data-label="${esc(row.label)}" data-custom="${row.is_custom?'true':'false'}"><label><input name="active" type="checkbox" ${row.active!==false?'checked':''}><span class="sr-only">Actif</span></label><label><input name="default_method" type="radio" value="${esc(row.code)}" ${row.is_default?'checked':''}><span class="sr-only">Par défaut</span></label><b>${esc(row.label)}</b><input name="position" type="number" min="0" value="${Number(row.position)||0}"><input name="details" value="${esc(row.details||'')}" placeholder="Ex. coordonnées ou consigne">${row.is_custom?button('Supprimer',`PilozModern.deletePaymentSetting('method','${row.id}')`,'btn-ghost','type="button"'):''}</div>`).join('')}</div><h3>Délais de paiement</h3><div class="payment-config-table"><div class="payment-config-head"><span>Actif</span><span>Par défaut</span><span>Délai</span><span>Ordre</span><span>Règle</span><span></span></div>${terms.map(row=>`<div class="payment-config-row" data-payment-term data-id="${esc(row.id||'')}" data-code="${esc(row.code)}" data-label="${esc(row.label)}" data-days="${row.days??''}" data-rule="${esc(row.calculation_rule||'days')}" data-custom="${row.is_custom?'true':'false'}"><label><input name="active" type="checkbox" ${row.active!==false?'checked':''}><span class="sr-only">Actif</span></label><label><input name="default_term" type="radio" value="${esc(row.code)}" ${row.is_default?'checked':''}><span class="sr-only">Par défaut</span></label><b>${esc(row.label)}</b><input name="position" type="number" min="0" value="${Number(row.position)||0}"><input name="details" value="${esc(row.details||'')}" placeholder="Informations complémentaires">${row.is_custom?button('Supprimer',`PilozModern.deletePaymentSetting('term','${row.id}')`,'btn-ghost','type="button"'):''}</div>`).join('')}</div><div class="modern-form-actions">${button('Enregistrer les paiements et délais','','btn-p','type="submit"')}</div></form></section>`;}
 const renderSalesSettingsBase=renderSalesSettings;
 renderSalesSettings=function(state){renderSalesSettingsBase(state);const legacy=document.getElementById('sales-payment-form')?.closest('.phase1-card');if(legacy)legacy.outerHTML=paymentConfiguration(state);};
 function paymentTableMissing(error){return['PGRST205','42P01'].includes(String(error?.code||''))||/Could not find the table|does not exist|schema cache/i.test(String(error?.message||''));}
async function savePaymentConfiguration(){const state=app().getState(),methodNodes=[...document.querySelectorAll('[data-payment-method]')],termNodes=[...document.querySelectorAll('[data-payment-term]')],defaultMethod=document.querySelector('[name="default_method"]:checked')?.value,defaultTerm=document.querySelector('[name="default_term"]:checked')?.value,methods=methodNodes.map(node=>({company_id:state.companyId,code:node.dataset.code,label:node.dataset.label,active:node.querySelector('[name="active"]').checked,is_default:node.dataset.code===defaultMethod,position:Number(node.querySelector('[name="position"]').value)||0,details:node.querySelector('[name="details"]').value||null,is_custom:node.dataset.custom==='true'})),terms=termNodes.map(node=>({company_id:state.companyId,code:node.dataset.code,label:node.dataset.label,days:node.dataset.days===''?null:Number(node.dataset.days),calculation_rule:node.dataset.rule||'days',active:node.querySelector('[name="active"]').checked,is_default:node.dataset.code===defaultTerm,position:Number(node.querySelector('[name="position"]').value)||0,details:node.querySelector('[name="details"]').value||null,is_custom:node.dataset.custom==='true'}));if(!methods.some(row=>row.active)||!terms.some(row=>row.active)){notify('Activez au moins un mode et un délai de paiement.','error');return;}if(!methods.some(row=>row.is_default&&row.active)||!terms.some(row=>row.is_default&&row.active)){notify('Le mode et le délai par défaut doivent être actifs.','error');return;}try{try{const noMethodDefault=methods.map(row=>({...row,is_default:false})),noTermDefault=terms.map(row=>({...row,is_default:false})),requestOptions=rows=>({method:'POST',headers:{Prefer:'resolution=merge-duplicates,return=minimal'},body:api().serializeBody(rows)});await api().request('/rest/v1/payment_methods?on_conflict=company_id,code',requestOptions(noMethodDefault));await api().request('/rest/v1/payment_terms?on_conflict=company_id,code',requestOptions(noTermDefault));await api().request('/rest/v1/payment_methods?on_conflict=company_id,code',requestOptions(methods));await api().request('/rest/v1/payment_terms?on_conflict=company_id,code',requestOptions(terms));}catch(error){if(!paymentTableMissing(error))throw error;}await api().request('/rest/v1/company_document_settings?on_conflict=company_id',{method:'POST',headers:{Prefer:'resolution=merge-duplicates,return=minimal'},body:api().serializeBody({company_id:state.companyId,default_payment_method:defaultMethod,default_payment_terms:defaultTerm,accepted_payment_methods:methods.filter(row=>row.active).map(row=>row.label)})});await app().refresh();notify('Modes et délais de paiement enregistrés.','success');}catch(error){notify(error.message,'error');}}
 function openCustomPaymentTerm(){showDrawer('Ajouter un délai personnalisé',`<form id="custom-payment-term-form" class="modern-form" onsubmit="event.preventDefault();PilozModern.saveCustomPaymentTerm()">${field('Libellé *','label','','text','required')}${field('Nombre de jours','days',30,'number','min="0" max="365"')}<label class="modern-field"><span>Règle</span><select name="calculation_rule"><option value="days">Nombre de jours</option><option value="receipt">À réception</option><option value="end_of_month">Fin de mois</option><option value="days_end_of_month">Jours fin de mois</option></select></label>${field('Informations complémentaires','details')}<div class="modern-form-actions">${button('Annuler','PilozModern.closeDrawer()','btn-ghost')}${button('Ajouter','','btn-p','type="submit"')}</div></form>`);}
 async function saveCustomPaymentTerm(){const state=app().getState(),form=document.getElementById('custom-payment-term-form');if(!form?.reportValidity())return;const raw=Object.fromEntries(new FormData(form)),code='custom_'+String(raw.label).toLocaleLowerCase('fr').normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^a-z0-9]+/g,'_').replace(/^_|_$/g,'').slice(0,40)+'_'+Date.now().toString().slice(-4);try{await api().insert('payment_terms',{company_id:state.companyId,code,label:raw.label.trim(),days:Number(raw.days)||0,calculation_rule:raw.calculation_rule,active:true,is_default:false,position:1000,is_custom:true,details:raw.details||null});closeDrawer();await app().refresh();notify('Délai personnalisé ajouté.','success');}catch(error){notify(error.message,'error');}}
async function deletePaymentSetting(kind,id){if(!id)return;const state=app().getState(),isMethod=kind==='method',rows=isMethod?state.data.paymentMethods||[]:state.data.paymentTerms||[],row=rows.find(item=>item.id===id);if(!row)return;const values=new Set([row.code,row.label,row.name].filter(Boolean).map(String)),field=isMethod?'payment_method':'payment_terms',defaultValue=isMethod?state.data.docSettings?.[0]?.default_payment_method:state.data.docSettings?.[0]?.default_payment_terms,used=(state.data.documents||[]).some(document=>values.has(String(document[field]||'')))||values.has(String(defaultValue||''));if(used){notify('Ce réglage est utilisé par un document ou défini par défaut. Désactivez-le au lieu de le supprimer.','error');return;}if(!confirm('Supprimer ce réglage personnalisé ?'))return;try{await api().remove(isMethod?'payment_methods':'payment_terms',id);await app().refresh();notify('Réglage supprimé.','success');}catch(error){notify(error.message,'error');}}
 async function saveSalesTax(){const state=app().getState(),data=Object.fromEntries(new FormData(document.getElementById('sales-tax-form')));try{await api().upsertCompanySettings(state.companyId,data);await app().refresh();notify('Devise enregistrée.','success');}catch(error){notify(error.message,'error');}}

 function renderPurchasesSettings(state){const docs=state.data.docSettings?.[0]||{},erp=state.data.erpSettings?.[0]||{};document.getElementById('main').innerHTML=header('Achats','Numérotation et conditions par défaut pour vos commandes fournisseurs.')+`<div class="modern-settings-grid"><section class="phase1-card"><h2>Numérotation & conditions</h2><p class="modern-card-desc">Appliquées aux nouvelles commandes fournisseurs.</p><form id="purchases-settings-form" class="modern-form" onsubmit="event.preventDefault();PilozModern.savePurchasesSettings()">${field('Préfixe commandes fournisseurs','purchase_order_prefix',docs.purchase_order_prefix||'BCF')}${selectField('Conditions fournisseurs par défaut','default_supplier_terms',pairs(phase1PaymentTerms||['30 jours']),erp.default_supplier_terms)}<div class="modern-form-actions">${button('Enregistrer','','btn-p','type="submit"')}</div></form></section><section class="phase1-card"><h2>Fournisseurs & commandes</h2><p class="modern-card-desc">La gestion opérationnelle se fait depuis les pages dédiées.</p>${button('Fournisseurs',`PilozApp.go('purchases/suppliers')`,'btn-o')}${button('Commandes fournisseurs',`PilozApp.go('purchases/orders')`,'btn-o')}${button('Réceptions',`PilozApp.go('purchases/receipts')`,'btn-o')}</section></div>`;}
