 function renderDocumentsSettings(state){const docs=state.data.docSettings?.[0]||{};document.getElementById('main').innerHTML=header('Documents','Mentions légales, langue et modèles utilisés sur vos devis et factures.')+`<div class="modern-settings-grid"><section class="phase1-card"><h2>Mentions & langue</h2><p class="modern-card-desc">Textes affichés en pied de vos documents commerciaux.</p><form id="documents-settings-form" class="modern-form" onsubmit="event.preventDefault();PilozModern.saveDocumentsSettings()">${selectField('Langue des documents','document_language',DOCUMENT_LANGUAGE_OPTIONS,docs.document_language||'fr')}<label class="modern-field full"><span>Mentions légales</span><textarea name="legal_notice">${esc(docs.legal_notice||'')}</textarea></label><label class="modern-field full"><span>Indemnité de recouvrement</span><textarea name="collection_fee_notice">${esc(docs.collection_fee_notice||'')}</textarea></label><label class="modern-field full"><span>Mention visible</span><textarea name="visible_mention">${esc(docs.visible_mention||'')}</textarea></label><div class="modern-form-actions">${button('Enregistrer','','btn-p','type="submit"')}</div></form></section><section class="phase1-card"><h2>Modèles de documents</h2><p class="modern-card-desc">Couleurs, typographies, en-têtes et pieds de page se personnalisent dans l’éditeur de modèles.</p>${button('Ouvrir l’éditeur de modèles',`PilozApp.go('settings/templates')`,'btn-p')}</section></div>`;}
