 function renderAccountingSettings(state){const settings=state.data.settings?.[0]||{};document.getElementById('main').innerHTML=header('Comptabilité','Exercice comptable et régime de TVA déclaratif.')+`<div class="modern-settings-grid"><section class="phase1-card"><h2>Exercice comptable & TVA</h2><p class="modern-card-desc">Utilisé pour vos exports comptables et vos rapports.</p><form id="accounting-settings-form" class="modern-form" onsubmit="event.preventDefault();PilozModern.saveAccountingSettings()">${field('Début de l’exercice comptable (MM-JJ)','fiscal_year_start',settings.fiscal_year_start||'01-01')}${field('Fréquence de déclaration de TVA','vat_frequency',settings.vat_frequency)}${field('Franchise en base','vat_franchise',settings.vat_franchise)}<div class="modern-form-actions">${button('Enregistrer','','btn-p','type="submit"')}</div></form></section></div>`;}
