 function renderUsersSettings(state){const members=state.data.members||[],roles=[['member','Membre historique'],['billing','Facturation'],['sales','Commercial'],['accounting','Comptabilité'],['read_only','Lecture seule'],['auditor','Auditeur'],['admin','Administrateur'],['owner','Propriétaire']];document.getElementById('main').innerHTML=header('Utilisateurs, rôles & permissions','Gérez les accès de votre équipe. Les opérations fiscales sensibles appliquent le moindre privilège côté base.')+`<div class="modern-settings-grid" style="grid-template-columns:1fr"><section class="phase1-card"><h2>Membres</h2><p class="modern-card-desc">Les rôles Facturation, Commercial, Comptabilité, Lecture seule et Auditeur séparent les responsabilités. Toute modification sensible est journalisée.</p><div class="phase1-table-wrap"><table class="phase1-table"><tr><th>Utilisateur</th><th>Rôle</th><th>Prix d’achat</th><th>Marges</th><th>Ajustements stock</th></tr>${members.map(member=>{const p=member.permissions||{};return`<tr><td class="phase1-mono">${esc(member.user_id===global.PilozRuntime.session.user_id?'Vous':member.user_id.slice(0,8))}</td><td><select onchange="PilozApp.updateMember('${member.user_id}','role',this.value)" ${member.role==='owner'?'disabled':''}>${roles.map(([value,label])=>`<option value="${value}" ${member.role===value?'selected':''}>${label}</option>`).join('')}</select></td>${['view_purchase_prices','view_margins','adjust_stock'].map(key=>`<td><input type="checkbox" ${p[key]?'checked':''} onchange="PilozApp.updateMember('${member.user_id}','${key}',this.checked)"></td>`).join('')}</tr>`;}).join('')||'<tr><td colspan="5">Aucun membre.</td></tr>'}</table></div></section></div>`;}

 function renderSecuritySettingsModern(state){document.getElementById('main').innerHTML=header('Sécurité','Session et connexion à votre compte.')+`<div class="modern-settings-grid"><section class="phase1-card"><h2>Session</h2><p>Connecté en tant que <b>${esc(global.PilozRuntime.session.email||'—')}</b></p>${button('Se déconnecter','deconnecter()','btn-o')}</section><section class="phase1-card"><h2>Isolation des données</h2><p class="modern-card-desc">Chaque entreprise est strictement isolée : vos données ne sont jamais visibles par une autre entreprise (sécurité appliquée au niveau de la base de données).</p></section></div>`;}

 const DEFAULT_PLANS=[{key:'essential',name:'Essentiel',price_monthly_cents:2900,price_annual_cents:29000,max_users:1},{key:'pro',name:'Pro',price_monthly_cents:5900,price_annual_cents:59000,max_users:5},{key:'business',name:'Business',price_monthly_cents:9900,price_annual_cents:99000,max_users:15}];
 const SUBSCRIPTION_STATUS_META={trialing:{label:'Essai gratuit',tone:'info'},active:{label:'Actif',tone:'success'},past_due:{label:'Paiement en attente',tone:'warning'},canceled:{label:'Résilié',tone:'danger'},suspended:{label:'Suspendu',tone:'danger'},expired:{label:'Expiré',tone:'danger'}};
 const COMPARE_TABLE=[
  ['Gestion commerciale',[['Clients et prospects',{essential:true,pro:true,business:true}],['Catalogue d’articles et services',{essential:true,pro:true,business:true}]]],
  ['Devis et factures',[['Devis',{essential:true,pro:true,business:true}],['Factures et avoirs',{essential:true,pro:true,business:true}],['Factures d’acompte et de solde',{essential:false,pro:true,business:true}],['Factures récurrentes',{essential:false,pro:true,business:true}]]],
  ['Suivi commercial',[['Suivi commercial et pipeline',{essential:true,pro:true,business:true}],['Relances manuelles',{essential:true,pro:true,business:true}],['Relances automatiques',{essential:false,pro:true,business:true}]]],
  ['Automatisations',[['Automatisations du pipeline',{essential:false,pro:true,business:true}]]],
  ['Achats',[['Achats et fournisseurs',{essential:false,pro:true,business:true}],['Commandes fournisseurs',{essential:false,pro:true,business:true}]]],
  ['Stock',[['Gestion de stock',{essential:false,pro:true,business:true}],['Plusieurs entrepôts',{essential:false,pro:false,business:true}]]],
  ['Modèles',[['Modèles standards',{essential:true,pro:true,business:true}],['Modèles personnalisables avancés',{essential:false,pro:true,business:true}]]],
  ['Tableau de bord',[['Tableau de bord essentiel',{essential:true,pro:true,business:true}],['Tableaux de bord avancés',{essential:false,pro:true,business:true}],['Rapports de marge',{essential:false,pro:true,business:true}]]],
  ['Utilisateurs',[['Utilisateurs inclus',{essential:'1',pro:'5',business:'15'}],['Rôles et permissions avancés',{essential:false,pro:false,business:true}]]],
  ['Support',[['Support e-mail',{essential:true,pro:true,business:true}],['Support prioritaire',{essential:false,pro:true,business:true}],['Support prioritaire renforcé',{essential:false,pro:false,business:true}]]]
 ];
 function renderCompareTable(){return`<details class="phase1-card"><summary style="cursor:pointer;font:730 1rem 'Albert Sans';list-style:none">Comparer toutes les fonctionnalités</summary><div class="compare-table-wrap" style="margin-top:14px"><table class="modern-table"><thead><tr><th>Fonctionnalité</th><th>Essentiel</th><th>Pro</th><th>Business</th></tr></thead><tbody>${COMPARE_TABLE.map(([cat,rows])=>`<tr><td colspan="4" style="background:var(--surface-secondary);font-weight:700">${esc(cat)}</td></tr>${rows.map(([label,vals])=>`<tr><td>${esc(label)}</td>${['essential','pro','business'].map(k=>`<td>${typeof vals[k]==='string'?esc(vals[k]):vals[k]?'✓':'—'}</td>`).join('')}</tr>`).join('')}`).join('')}</tbody></table></div></details>`;}
 function planCardAction(plan,sub,billing){
  if(plan.key===sub.plan_key)return button('Offre actuelle','','btn-ghost','disabled');
  if(sub.status==='trialing'||sub.status==='canceled'||sub.status==='expired')return button(`Choisir ${plan.name}`,`PilozModern.choosePlanFromCard('${plan.key}','${billing}')`,'btn-p');
  return button(`Passer à ${plan.name}`,`PilozModern.requestPlanChange('${plan.key}')`,'btn-o');
 }
 function renderSubscriptionSettings(state){
  const sub=state.data.subscription?.[0]||null,plans=state.data.plans?.[0]?.key?state.data.plans:DEFAULT_PLANS;
  if(!sub){
   document.getElementById('main').innerHTML=header('Abonnement et facturation','Gérez votre offre Piloz, vos limites d’utilisation et vos informations de facturation.')+
   `<section class="phase1-card"><h2>Abonnement non initialisé</h2><p class="modern-card-desc">La configuration des abonnements (migration 202607210012_subscriptions_and_plans.sql) n’a pas encore été appliquée à cette base Supabase. Aucune limitation n’est appliquée tant que ce n’est pas fait. Contactez votre administrateur technique pour l’exécuter.</p></section>`;
   return;
  }
  const plan=plans.find(p=>p.key===sub.plan_key)||plans[0];
  const members=state.data.members||[],clients=state.data.clients||[],documents=state.data.documents||[];
  const labels=global.PilozSubscription?.FEATURE_LABELS||{};
  const trialExpired=global.PilozSubscription?.getSubscriptionStatus?.()==='expired';
  const statusKey=trialExpired?'expired':sub.status;
  const status=SUBSCRIPTION_STATUS_META[statusKey]||{label:sub.status,tone:'info'};
  const billing=ui.subscriptionBilling||'monthly';
  const usersUsed=members.length,usersMax=plan.max_users||1,userPct=Math.min(100,Math.round(usersUsed/usersMax*100)),userTone=userPct>=100?'danger':userPct>=80?'warn':'';
  let primaryActions='';
  const scrollToPlans=`document.getElementById('subscription-plans')?.scrollIntoView({behavior:'smooth'})`;
  if(statusKey==='expired'||sub.status==='trialing'){primaryActions=button('Choisir une offre',scrollToPlans,'btn-p');}
  else if(sub.status==='active'){primaryActions=button('Changer d’offre',scrollToPlans,'btn-p')+(sub.billing_interval==='monthly'?button('Passer à la facturation annuelle','PilozModern.switchToAnnual()','btn-o'):'')+button('Gérer le moyen de paiement','PilozModern.manageBilling()','btn-o')+(sub.cancellation_at_period_end?'':button('Résilier l’abonnement','PilozModern.cancelSubscription()','btn-ghost'));}
  else if(sub.status==='past_due'||sub.status==='suspended'){primaryActions=button('Gérer le moyen de paiement','PilozModern.manageBilling()','btn-p');}
  else if(sub.status==='canceled'){primaryActions=(sub.subscription_ends_at&&new Date(sub.subscription_ends_at)>new Date())?button('Réactiver l’abonnement','PilozModern.reactivateSubscription()','btn-p'):button('Choisir une offre',scrollToPlans,'btn-p');}
  if(sub.cancellation_at_period_end&&sub.status==='active')primaryActions+=button('Réactiver l’abonnement','PilozModern.reactivateSubscription()','btn-o');
  const alertBlock=statusKey==='expired'?`<div class="modern-status danger" style="display:block;padding:10px 12px;margin-bottom:14px">Votre essai gratuit est terminé. Choisissez une offre pour continuer à utiliser Piloz.</div>`
   :sub.status==='suspended'?`<div class="modern-status danger" style="display:block;padding:10px 12px;margin-bottom:14px">Votre abonnement est suspendu. Mettez à jour votre moyen de paiement pour réactiver votre compte.</div>`
   :sub.status==='past_due'?`<div class="modern-status warning" style="display:block;padding:10px 12px;margin-bottom:14px">Le dernier paiement n’a pas pu être prélevé. Vérifiez votre moyen de paiement.</div>`:'';
  document.getElementById('main').innerHTML=header('Abonnement et facturation','Gérez votre offre Piloz, vos limites d’utilisation et vos informations de facturation.')+
  `${alertBlock}
  <section class="phase1-card">
   <div style="display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:10px">
    <div><h2 style="margin-bottom:4px">Piloz ${esc(plan.name)}</h2><span class="modern-status ${status.tone}">${esc(status.label)}</span></div>
    <div style="font-size:1.4rem;font-weight:740">${money((sub.billing_interval==='annual'?plan.price_annual_cents:plan.price_monthly_cents)/100)}<span style="font-size:.8rem;font-weight:600;color:var(--text-muted)"> HT ${sub.billing_interval==='annual'?'/ an':'/ mois'}</span></div>
   </div>
   <div class="modern-kpis" style="margin-top:14px">
    ${sub.subscription_started_at?kpi('Début de l’abonnement',date(sub.subscription_started_at)):''}
    ${sub.status==='trialing'&&sub.trial_ends_at?kpi('Fin de l’essai',date(sub.trial_ends_at)):''}
    ${sub.subscription_ends_at?kpi('Prochaine échéance',date(sub.subscription_ends_at)):''}
    ${sub.cancellation_at_period_end?kpi('Résiliation prévue le',date(sub.subscription_ends_at||sub.trial_ends_at)):''}
    ${kpi('Utilisateurs',`${usersUsed} / ${usersMax}`)}
   </div>
   <div style="margin-top:14px;display:flex;gap:8px;flex-wrap:wrap">${primaryActions}</div>
  </section>
  <section class="phase1-card"><h2>Utilisation de votre offre</h2>
   <div class="usage-bar"><div class="usage-bar-head"><span>Utilisateurs</span><b>${usersUsed} / ${usersMax}</b></div><div class="usage-bar-track"><div class="usage-bar-fill ${userTone}" style="width:${userPct}%"></div></div></div>
   <div class="usage-bar"><div class="usage-bar-head"><span>Clients et prospects</span><b>${clients.length} · Illimité</b></div><div class="usage-bar-track"><div class="usage-bar-fill" style="width:6%"></div></div></div>
   <div class="usage-bar"><div class="usage-bar-head"><span>Devis et factures</span><b>${documents.length} · Illimité</b></div><div class="usage-bar-track"><div class="usage-bar-fill" style="width:6%"></div></div></div>
  </section>
  <section class="phase1-card" id="subscription-plans">
   <div style="display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:10px">
    <h2>Comparer les offres</h2>
    <div class="plan-toggle"><button type="button" class="${billing==='monthly'?'active':''}" onclick="PilozModern.setSubscriptionBilling('monthly')">Mensuel</button><button type="button" class="${billing==='annual'?'active':''}" onclick="PilozModern.setSubscriptionBilling('annual')">Annuel</button></div>
   </div>
   <div class="plan-cards">${plans.map(p=>{const planFeatures=global.PilozSubscription?.PLAN_FEATURES?.[p.key]||[],price=billing==='annual'?p.price_annual_cents:p.price_monthly_cents;return`<div class="plan-card ${p.key==='pro'?'highlight':''}"><h3>Piloz ${esc(p.name)}</h3><div class="plan-card-price">${money(price/100)}<span> HT ${billing==='annual'?'/ an':'/ mois'}</span></div><p class="modern-card-desc">${p.max_users} utilisateur${p.max_users>1?'s':''} inclus</p><ul>${planFeatures.slice(0,5).map(k=>`<li>✓ ${esc(labels[k]||k)}</li>`).join('')}</ul><div class="actions">${planCardAction(p,sub,billing)}</div></div>`;}).join('')}</div>
   <p class="modern-card-desc">Plus de 15 utilisateurs ou besoins spécifiques ? ${button('Contacter Piloz',`location.href='mailto:${esc(ADMIN_EMAIL)}?subject=${encodeURIComponent('Offre personnalisée Piloz')}'`,'btn-ghost','type="button"')}</p>
  </section>
  ${renderCompareTable()}
  <section class="phase1-card"><h2>Informations de facturation</h2>
   <p class="modern-card-desc">Aucun moyen de paiement en ligne n’est encore connecté (intégration Stripe à finaliser). Les informations ci-dessous reprennent votre profil entreprise.</p>
   <dl style="display:grid;gap:6px;margin:12px 0">
    <div style="display:flex;justify-content:space-between"><dt>Raison sociale</dt><dd>${dash(state.data.settings?.[0]?.legal_name)}</dd></div>
    <div style="display:flex;justify-content:space-between"><dt>E-mail de facturation</dt><dd>${dash(state.data.settings?.[0]?.email)}</dd></div>
    <div style="display:flex;justify-content:space-between"><dt>N° TVA</dt><dd>${dash(state.data.settings?.[0]?.vat_number)}</dd></div>
    <div style="display:flex;justify-content:space-between"><dt>Moyen de paiement</dt><dd>Non configuré</dd></div>
   </dl>
   <div class="modern-form-actions" style="border:0;justify-content:flex-start;padding-top:0">${button('Modifier les informations',`PilozApp.go('settings/company/legal')`,'btn-o')}${button('Modifier le moyen de paiement','PilozModern.manageBilling()','btn-ghost')}</div>
  </section>
  <section class="phase1-card"><h2>Historique des factures</h2>${empty('Aucune facture pour le moment','L’historique de facturation apparaîtra ici une fois Stripe connecté.')}</section>`;
 }
 function setSubscriptionBilling(interval){ui.subscriptionBilling=interval;app().render();}
 async function switchToAnnual(){const state=app().getState(),sub=state.data.subscription?.[0];if(!sub)return;try{await api().rpc('choose_plan',{target_company_id:state.companyId,target_plan_key:sub.plan_key,target_billing_interval:'annual'});await app().refresh();notify('Facturation annuelle sélectionnée.','success');}catch(error){notify(error.message,'error');}}
 async function choosePlanFromCard(planKey,interval){const state=app().getState();try{await api().rpc('choose_plan',{target_company_id:state.companyId,target_plan_key:planKey,target_billing_interval:interval});await app().refresh();notify('Offre mise à jour pour la période d’essai.','success');}catch(error){notify(error.message,'error');}}
 function requestPlanChange(planKey){const names={essential:'Essentiel',pro:'Pro',business:'Business'};location.href=`mailto:${ADMIN_EMAIL}?subject=${encodeURIComponent('Changer mon offre Piloz vers '+(names[planKey]||planKey))}`;}
 function manageBilling(){notify('La gestion du moyen de paiement en ligne sera disponible une fois l’intégration Stripe finalisée.','info');}
 async function cancelSubscription(){if(!confirm('Résilier l’abonnement en fin de période ?'))return;const state=app().getState();try{await api().rpc('cancel_subscription',{target_company_id:state.companyId});await app().refresh();notify('Résiliation programmée.','success');}catch(error){notify(error.message,'error');}}
 async function reactivateSubscription(){const state=app().getState();try{await api().rpc('reactivate_subscription',{target_company_id:state.companyId});await app().refresh();notify('Abonnement réactivé.','success');}catch(error){notify(error.message,'error');}}

 function renderDataSettings(state){const logs=state.data.activityLogs||[];document.getElementById('main').innerHTML=header('Données','Export, journal d’activité et gestion de votre compte.')+`<div class="modern-settings-grid"><section class="phase1-card"><h2>Export</h2><p class="modern-card-desc">Exportez vos données depuis les pages dédiées.</p>${button('Devis (CSV)',`PilozApp.go('sales/quotes')`,'btn-o')}${button('Factures (CSV)',`PilozApp.go('sales/invoices')`,'btn-o')}</section><section class="phase1-card" style="grid-column:span 2"><h2>Journal d’activité</h2><div class="modern-table-shell">${logs.length?`<table class="modern-table"><thead><tr><th>Date</th><th>Action</th><th>Élément</th></tr></thead><tbody>${logs.slice(0,50).map(log=>`<tr><td>${datetime(log.created_at)}</td><td>${esc(log.action)}</td><td>${esc(log.entity_type)}</td></tr>`).join('')}</tbody></table>`:empty('Aucune activité récente','Les actions importantes (validation de facture, paiement…) apparaîtront ici.')}</div></section><section class="phase1-card"><h2>Suppression du compte</h2><p class="modern-card-desc">La suppression définitive de votre compte et de vos données est irréversible. Contactez le support pour la déclencher en toute sécurité.</p>${button('Contacter le support',`location.href='mailto:${esc(ADMIN_EMAIL)}?subject=${encodeURIComponent('Suppression de mon compte Piloz')}'`,'btn-ghost')}</section></div>`;}
 const renderDocumentsWithAdvancedFilters=renderDocuments;
 renderDocuments=function(state,kind){const sentMap=new Map((state.data.documentDeliveryMeta||[]).map(row=>[row.id,row.sent_at]));(state.data.documents||[]).forEach(row=>{if(!row.sent_at&&sentMap.has(row.id))row.sent_at=sentMap.get(row.id);});return renderDocumentsWithAdvancedFilters(state,kind);};

 function renderRoute(route,state){const path=hash();if(route==='dashboard'){renderDashboard(state);return true;}if(route==='crm-overview'){crmOverview(state);return true;}if(route==='pipeline'){renderPipeline(state);return true;}if(route==='opportunities'){renderOpportunities(state);return true;}if(route==='prospects'){renderProspects(state);return true;}if(route==='activities'){renderActivities(state);return true;}if(route==='crm-reminders'){renderReminders(state,true);return true;}if(route==='sales-overview'){salesOverview(state);return true;}if(route==='documents:quote'){renderDocuments(state,'quote');return true;}if(route==='documents:invoice'){renderDocuments(state,'invoice');return true;}if(route==='sales-payments'){renderPayments(state);return true;}if(route==='sales-due-dates'){renderSchedules(state);return true;}if(route==='sales-reminders-center'){renderReminders(state,false);return true;}if(route==='purchases-overview'){purchasesOverview(state);return true;}if(route==='purchase-invoices'){renderSupplierInvoices(state);return true;}if(route==='reports'){renderReports(state);return true;}if(route==='settings'&&path==='settings/company'){renderCompanyOverview(state);return true;}if(route==='settings'&&path==='settings/company/profile'){renderCompanyProfile(state);return true;}if(route==='settings'&&path==='settings/company/contacts'){renderCompanyContacts(state);return true;}if(route==='settings'&&path==='settings/company/addresses'){renderCompanyAddresses(state);return true;}if(route==='settings'&&path==='settings/company/legal'){renderCompanyLegal(state);return true;}if(route==='settings'&&path==='settings/company/tax'){renderCompanyTax(state);return true;}if(route==='settings'&&path==='settings/company/bank'){renderCompanyBank(state);return true;}if(route==='settings'&&path==='settings/sales'){renderSalesSettings(state);return true;}if(route==='settings'&&path==='settings/purchases'){renderPurchasesSettings(state);return true;}if(route==='settings'&&path==='settings/stock'){renderStockSettings(state);return true;}if(route==='settings'&&path==='settings/documents'){renderDocumentsSettings(state);return true;}if(route==='settings'&&path==='settings/accounting'){renderAccountingSettings(state);return true;}if(route==='settings'&&path==='settings/pipeline'){renderPipelineSettings(state);return true;}if(route==='settings'&&path==='settings/users'){renderUsersSettings(state);return true;}if(route==='settings'&&path==='settings/security'){renderSecuritySettingsModern(state);return true;}if(route==='settings'&&path==='settings/subscription'){renderSubscriptionSettings(state);return true;}if(route==='settings'&&path==='settings/data'){renderDataSettings(state);return true;}return false;}

 const renderRouteWithCompanyLogo=renderRoute;
 renderRoute=function(route,state){
  if(route==='settings'&&hash()==='settings/company/logo'){renderCompanyLogo(state);return true;}
  return renderRouteWithCompanyLogo(route,state);
 };

